import { catchAsync } from '@common/utils/catchAsync';
import { AccountService } from './account.service';
import { ApiError } from '@common/utils/ApiError';
import { IAccountFilter } from '@common/interfaces/accounts.interface';
import { RoleService } from '@modules/roles/role.service';
import { UserRoleDefined } from '@common/utils/enum';
import { AccountRoleService } from '@modules/accountRoles/accountRole.service';

const accountService = new AccountService();
const roleService = new RoleService();
const accountRoleService = new AccountRoleService();

export const createAccount = catchAsync(async (req, res) => {
    const newUser = await accountService.createAccount(req.body);
    if (!newUser) {
        throw new ApiError(500, 'Tạo tài khoản thất bại');
    }
    const roleUser = await roleService.getRoleByName(UserRoleDefined.User);
    await accountRoleService.createAccountRole({ roleId: String(roleUser._id), accountId: String(newUser.data._id) });
    res.status(201).json(newUser);
});

export const getAccountById = catchAsync(async (req, res) => {
    const account = await accountService.getAccountById(req.params.id);
    res.status(200).json(account);
});

export const getAccountByFilter = catchAsync(async (req, res) => {
    const filter: IAccountFilter = {
        page: req.query.page ? parseInt(String(req.query.page), 10) : 1,
        limit: req.query.limit ? parseInt(String(req.query.limit), 10) : 10,
        username: req.query.username ? String(req.query.username) : undefined,
        email: req.query.email ? String(req.query.email) : undefined,
        status: req.query.status ? String(req.query.status) : undefined,
    };
    const account = await accountService.getAccountsByFilter(filter);
    res.status(200).json(account);
});

export const updateAccount = catchAsync(async (req, res) => {
    const newUser = await accountService.updateAccount(req.params.id, req.body);
    res.status(200).json(newUser);
});

export const changePasswordAccount = catchAsync(async (req, res) => {
    const newUser = await accountService.changePasswordAccount(
        req.users.user,
        req.body.currentPassword,
        req.body.changePassword,
    );
    res.status(200).json(newUser);
});

export const deleteAccount = catchAsync(async (req, res) => {
    const deletedUser = await accountService.deleteAccount(req.params.id);
    res.status(200).json(deletedUser);
});

import { IAccountFilter, IAccountPayload, IAccounts } from '@common/interfaces/accounts.interface';
import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import AccountModel from './accounts.model';
import { ApiError } from '@common/utils/ApiError';
import { comparePassword, hashPassword } from '@common/utils/hashPassword';
import { QueryFilter } from 'mongoose';
import { AccountRoleService } from '../accountRoles/accountRole.service';

const accountRoleService = new AccountRoleService();

export class AccountService {
    public async createAccount(payload: IAccountPayload): Promise<IApiResponse<IAccounts>> {
        const exitedEmail = await AccountModel.findOne({
            $or: [{ email: payload.email }, { username: payload.email }],
        });
        if (exitedEmail) {
            throw new ApiError(400, 'Email đã tồn tại');
        }
        const exitedUsername = await AccountModel.findOne({
            $or: [{ email: payload.username }, { username: payload.username }],
        });
        if (exitedUsername) {
            throw new ApiError(400, 'Username đã tồn tại');
        }
        const newPassword = await hashPassword(payload.password);
        payload.password = newPassword;
        const newAccount = await AccountModel.create(payload);
        return {
            success: true,
            message: 'Account created successfully',
            data: newAccount,
        };
    }

    public async getAccountByUserName(username: string): Promise<IApiResponse<IAccounts>> {
        const account = await AccountModel.findOne({
            $or: [{ email: username }, { username: username }],
        });
        if (!account) {
            return {
                success: false,
                message: 'Không tìm thấy account',
                data: null,
            };
        }
        return {
            success: true,
            message: 'Đã tìm thấy account',
            data: account,
        };
    }

    public async getAccountById(id: string): Promise<IApiResponse<IAccounts>> {
        const account = await AccountModel.findById(id).select('-password');
        if (!account) {
            throw new ApiError(404, 'Không tìm thấy tài khoản');
        }
        return {
            success: true,
            message: 'Đã tìm thấy account',
            data: account,
        };
    }

    public async getOneAccount(filter: IAccountFilter): Promise<IApiResponse<IAccounts>> {
        const account = await AccountModel.findOne(filter);
        if (!account) {
            return {
                success: false,
                message: 'Không tìm thấy account',
                data: null,
            };
        }
        return {
            success: true,
            message: 'Đã tìm thấy account',
            data: account,
        };
    }

    public async getAccountsByFilter(filter: IAccountFilter): Promise<IPaginatedResponse<IAccounts>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const query: QueryFilter<IAccountFilter> = {};
        if (filter.email) {
            query.email = {
                $regex: `.*${filter.email}.*`,
                $options: 'i',
            };
        }
        if (filter.username) {
            query.username = {
                $regex: `.*${filter.username}.*`,
                $options: 'i',
            };
        }
        if (filter.status) {
            query.status = filter.status;
        }

        const aggregateQuery = [{ $match: query }, { $unset: 'password' }];
        const [records, countRecords] = await Promise.all([
            AccountModel.aggregate([
                ...aggregateQuery,
                { $sort: { createdAt: -1 } },
                { $skip: (page - 1) * limit },
                { $limit: limit },
                {
                    $lookup: {
                        from: 'employees',
                        localField: 'employeeId',
                        foreignField: '_id',
                        as: 'employee',
                    },
                },
                { $unwind: { path: '$employee', preserveNullAndEmptyArrays: true } },
                {
                    $addFields: {
                        fullName: '$employee.fullName',
                    },
                },
                { $project: { employee: 0 } },
            ]),
            AccountModel.aggregate([...aggregateQuery, { $count: 'count' }]),
        ]);
        const count = countRecords[0]?.count || 0;

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách account thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async updateAccount(id: string, payload: Partial<IAccountPayload>): Promise<IApiResponse<IAccounts>> {
        delete payload.password;

        if (payload.username) {
            const exitedUsername = await AccountModel.findOne({
                username: payload.username,
                _id: { $ne: id },
            });

            if (exitedUsername) {
                throw new ApiError(400, 'Username đã tồn tại');
            }
        }

        if (payload.email) {
            const exitedEmail = await AccountModel.findOne({
                email: payload.email,
                _id: { $ne: id },
            });

            if (exitedEmail) {
                throw new ApiError(400, 'Email đã tồn tại');
            }
        }

        const account = await AccountModel.findByIdAndUpdate(id, payload, { new: true }).select('-password');
        if (!account) {
            throw new ApiError(404, 'Không tìm thấy tài khoản');
        }
        return {
            success: true,
            message: 'Cập nhật tài khoản thành công',
            data: account,
        };
    }

    public async updateOneAccount(
        query: IAccountPayload,
        payload: Partial<IAccountPayload>,
    ): Promise<IApiResponse<IAccounts>> {
        const account = await AccountModel.findOneAndUpdate(query, payload, { new: true }).select('-password');
        if (!account) {
            throw new ApiError(404, 'Không tìm thấy tài khoản');
        }
        return {
            success: true,
            message: 'Cập nhật tài khoản thành công',
            data: account,
        };
    }

    public async deleteAccount(id: string): Promise<IApiResponse<IAccounts>> {
        await accountRoleService.deleteAccountRoleByAccountId(id);
        const account = await AccountModel.findByIdAndDelete(id);
        if (!account) {
            throw new ApiError(404, 'Không tìm thấy tài khoản');
        }
        return {
            success: true,
            message: 'Xóa tài khoản thành công',
            data: account,
        };
    }

    public async deleteAccountByEmployee(id: string): Promise<IApiResponse<IAccounts>> {
        const account = await AccountModel.findOneAndDelete({ employeeId: id });
        if (!account) {
            throw new ApiError(404, 'Không tìm thấy tài khoản');
        }
        await accountRoleService.deleteAccountRoleByAccountId(account._id.toString());
        return {
            success: true,
            message: 'Xóa tài khoản thành công',
            data: account,
        };
    }

    public async changePasswordAccount(
        user: IAccounts,
        currentPassword: string,
        changePassword: string,
    ): Promise<IApiResponse<IAccounts>> {
        const accPass = await AccountModel.findById(user._id).select('password');
        if (!accPass) {
            throw new ApiError(404, 'Không tìm thấy tài khoản');
        }

        const isMatch = await comparePassword(currentPassword, accPass.password);
        if (!isMatch) {
            throw new ApiError(400, 'Mật khẩu hiện tại không đúng');
        }

        if (currentPassword === changePassword) {
            throw new ApiError(400, 'Mật khẩu mới không được trùng với mật khẩu cũ');
        }

        const newPassword = await hashPassword(changePassword);
        const account = await AccountModel.findByIdAndUpdate(user._id, { password: newPassword, $inc: { tokenVersion: 1 }, }, { new: true }).select(
            '-password',
        );
        if (!account) {
            throw new ApiError(404, 'Không tìm thấy tài khoản');
        }

        return {
            success: true,
            message: 'Cập nhật mật khẩu tài khoản thành công',
            data: account,
        };
    }
}

import { catchAsync } from '@common/utils/catchAsync';
import { Request, Response } from 'express';
import { EmployeesService } from './employees.service';
import { IEmployeeFilter, IEmployeePermission } from '@common/interfaces/employee.interface';
import { DepartmentService } from '@modules/departments/department.service';
import { DEPARTMENT_BOF, IAccountStatus, INikoWalletStatus, UserRoleDefined } from '@common/utils/enum';
import { Types } from 'mongoose';
import { AccountService } from '@modules/accounts/account.service';
import { ACCOUNT_DEFAULT_PASSWORD } from '@common/config/environment';
import { IAccountPayload } from '@common/interfaces/accounts.interface';
import { AccountRoleService } from '@modules/accountRoles/accountRole.service';
import { RoleService } from '@modules/roles/role.service';
import { IDepartments } from '@common/interfaces/department.interface';
import { NikoWalletsService } from '@modules/nikoWallets/nikoWallets.service';

const employeesService = new EmployeesService();
const departmentService = new DepartmentService();
const accountService = new AccountService();
const accountRoleService = new AccountRoleService();
const roleService = new RoleService();
const nikoWalletsService = new NikoWalletsService();

export const createEmployee = catchAsync(async (req: Request, res: Response) => {
    const employee = await employeesService.createEmployee(req.body);
    if (employee.data) {
        const newAccount: IAccountPayload = {
            email: employee.data.email,
            password: ACCOUNT_DEFAULT_PASSWORD,
            username: employee.data.email,
            employeeId: employee.data._id.toString(),
            status: IAccountStatus.Active,
        };
        const account = await accountService.createAccount(newAccount);
        if (account.data) {
            const role = await roleService.getRoleByName(UserRoleDefined.User);
            if (role) {
                await accountRoleService.createAccountRole({
                    accountId: account.data._id?.toString(),
                    roleId: role._id?.toString(),
                });
            }
        }
        await nikoWalletsService.createNikoWallet({
            employeeId: employee.data._id.toString(),
            status: INikoWalletStatus.ACTIVE,
        });
    }
    res.status(201).json(employee);
});

export const getEmployeesByFilter = catchAsync(async (req: Request, res: Response) => {
    const filter: IEmployeeFilter = {
        page: req.query.page ? parseInt(String(req.query.page), 10) : 1,
        limit: req.query.limit ? parseInt(String(req.query.limit), 10) : 10,
        email: req.query.email ? String(req.query.email) : undefined,
        departmentId: req.query.departmentId ? new Types.ObjectId(String(req.query.departmentId)) : undefined,
        departmentIds: req.query.departmentIds
            ? String(req.query.departmentIds)
                .split(',')
                .map((item) => new Types.ObjectId(String(item)))
            : undefined,
        fullName: req.query.fullName ? String(req.query.fullName) : undefined,
        code: req.query.code ? String(req.query.code) : undefined,
        status: req.query.status ? String(req.query.status) : undefined,
    };
    const employees = await employeesService.getEmployeeByFilter(filter, req.users);
    res.status(200).json(employees);
});

export const getEmployeeById = catchAsync(async (req: Request, res: Response) => {
    const employee = await employeesService.getEmployeeById(String(req.params.id), req.users);
    res.status(200).json(employee);
});

export const updateEmployee = catchAsync(async (req: Request, res: Response) => {
    const employee = await employeesService.updateEmployee(String(req.params.id), req.body, req.users);
    if (req.body.email && employee.data) {
        await accountService.updateOneAccount({ employeeId: employee.data._id.toString() }, { email: req.body.email });
    }
    res.status(200).json(employee);
});

export const deleteEmployee = catchAsync(async (req: Request, res: Response) => {
    const employee = await employeesService.deleteEmployee(String(req.params.id), req.users);
    if (employee.data) {
        await accountService.deleteAccountByEmployee(employee.data._id.toString());
    }
    res.status(200).json(employee);
});

export const getPermissionEmployee = catchAsync(async (req: Request, res: Response) => {
    const managedDepartment = await departmentService.getDepartmentsByFilter({ managerId: req.users.user.employeeId });

    const managedDepartmentIds: string[] = managedDepartment.data
        ?.map((item) => item?._id?.toString())
        .filter((item) => !!item);

    const isInBoardOfManager: boolean = managedDepartment.data?.some((item) => item.code === DEPARTMENT_BOF.CODE);
    const permission: IEmployeePermission = {
        role: req.users.roles as UserRoleDefined,
        managedDepartmentIds: managedDepartmentIds,
        isInBoardOfManager,
    };

    const employee = await employeesService.getEmployeeById(req.users.user.employeeId?.toString(), req.users);
    if (employee.data?.departmentId) {
        if ((employee.data?.departmentId as unknown as IDepartments).code === DEPARTMENT_BOF.CODE) {
            const managerIds = await departmentService.getManagerIdDepartmentsId();
            if (managerIds?.length) {
                permission.managerIds = managerIds;
            }
        }
    }

    res.status(200).json(permission);
});

import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import { ApiError } from '@common/utils/ApiError';
import EmployeesModel from './employees.model';
import { IEmployeeFilter, IEmployeeGetOne, IEmployeePayload, IEmployees } from '@common/interfaces/employee.interface';
import { PipelineStage, QueryFilter } from 'mongoose';
import { getAccessibleEmployeeIds, IUserContext } from '@common/helpers/permission.helper';
import { DEPARTMENT_BOF, UserRoleDefined } from '@common/utils/enum';
import { IDepartments } from '@common/interfaces/department.interface';
import { AccountService } from '../accounts/account.service';

const accountService = new AccountService();

export class EmployeesService {
    public async createEmployee(payload: IEmployeePayload): Promise<IApiResponse<IEmployees>> {
        if (payload.email) {
            const exitedEmployee = await EmployeesModel.findOne({ email: payload.email });
            if (exitedEmployee) {
                throw new ApiError(400, 'Email của nhân viên đã tồn tại');
            }
        }

        if (payload.code) {
            const exitedEmployee = await EmployeesModel.findOne({ code: payload.code });
            if (exitedEmployee) {
                throw new ApiError(400, 'Mã của nhân viên đã tồn tại');
            }
        }

        if (payload.phone) {
            const exitedEmployee = await EmployeesModel.findOne({ phone: payload.phone });
            if (exitedEmployee) {
                throw new ApiError(400, 'Phone của nhân viên đã tồn tại');
            }
        }

        const newEmployee = await EmployeesModel.create(payload);
        return {
            success: true,
            message: 'Tạo nhân viên thành công',
            data: newEmployee,
        };
    }

    public async getOneEmployee(filter: IEmployeeGetOne): Promise<IApiResponse<IEmployees>> {
        const record = await EmployeesModel.findOne(filter);
        if (!record) {
            return {
                success: false,
                message: 'Không tìm thấy nhân viên',
                data: null,
            };
        }
        return {
            success: true,
            message: 'Đã thấy nhân viên',
            data: record,
        };
    }

    public async getEmployeeByFilter(
        filter: IEmployeeFilter,
        userContext: IUserContext,
    ): Promise<IPaginatedResponse<IEmployees>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const query: QueryFilter<IEmployeeFilter> = {};

        const accessibleIds = await getAccessibleEmployeeIds(userContext);
        if (accessibleIds !== null) {
            query._id = { $in: accessibleIds };
        }
        if (filter.fullName) {
            const fullNameFormat = filter.fullName.normalize('NFC');
            query.fullName = {
                $regex: `.*${fullNameFormat}.*`,
                $options: 'i',
            };
        }
        if (filter.email) {
            query.email = {
                $regex: `.*${filter.email}.*`,
                $options: 'i',
            };
        }
        if (filter.code) {
            query.code = {
                $regex: `.*${filter.code}.*`,
                $options: 'i',
            };
        }
        if (filter.status) {
            query.status = filter.status;
        }
        if (filter.departmentIds && filter.departmentIds.length > 0) {
            query.departmentId = { $in: filter.departmentIds };
        } else if (filter.departmentId) {
            query.departmentId = filter.departmentId;
        }
        const aggregateQuery: PipelineStage[] = [{ $match: query }, { $sort: { createdAt: -1 } }];

        const [records, docCounter] = await Promise.all([
            EmployeesModel.aggregate([
                ...aggregateQuery,
                { $skip: (page - 1) * limit },
                { $limit: limit },
                {
                    $lookup: {
                        from: 'departments',
                        localField: 'departmentId',
                        foreignField: '_id',
                        as: 'department',
                    },
                },
                {
                    $lookup: {
                        from: 'positions',
                        localField: 'positionId',
                        foreignField: '_id',
                        as: 'position',
                    },
                },
                {
                    $unwind: {
                        path: '$department',
                        preserveNullAndEmptyArrays: true,
                    },
                },
                {
                    $unwind: {
                        path: '$position',
                        preserveNullAndEmptyArrays: true,
                    },
                },
            ]),
            EmployeesModel.aggregate([...aggregateQuery, { $count: 'count' }]),
        ]);

        const count = docCounter[0]?.count || 0;
        return {
            data: records,
            success: true,
            message: 'Lấy danh sách nhân viên thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async getEmployeeById(id: string, userContext: IUserContext): Promise<IApiResponse<IEmployees>> {
        const record = await EmployeesModel.findById(id).populate('departmentId').populate('positionId');
        if (!record) {
            throw new ApiError(404, 'Không tìm thấy nhân viên này');
        }

        const accessibleIds = await getAccessibleEmployeeIds(userContext);
        if (accessibleIds !== null) {
            const isAccessible = accessibleIds.some((accId) => String(accId) === String(record._id));
            if (!isAccessible) {
                throw new ApiError(403, 'Bạn không có quyền xem thông tin nhân viên này');
            }
        }
        return {
            success: true,
            message: 'Đã thấy nhân viên',
            data: record,
        };
    }

    public async updateEmployee(
        id: string,
        payload: IEmployeePayload,
        userContext: IUserContext,
    ): Promise<IApiResponse<IEmployees>> {
        let isAdminOrBOF = userContext && (userContext.roles === UserRoleDefined.Admin || userContext.roles === UserRoleDefined.SuperAdmin || userContext.roles === UserRoleDefined.HR);

        if (!isAdminOrBOF && userContext?.user?.employeeId) {
            const requester = await EmployeesModel.findById(userContext.user.employeeId).populate('departmentId');
            if ((requester?.departmentId as unknown as IDepartments)?.code === DEPARTMENT_BOF.CODE) {
                isAdminOrBOF = true;
            }
        }

        if (userContext && userContext.roles === UserRoleDefined.User) {
            if (String(id) !== String(userContext.user?.employeeId) && !isAdminOrBOF) {
                throw new ApiError(403, 'Bạn không có quyền cập nhật thông tin nhân viên khác');
            }
        }

        if (!isAdminOrBOF) {
            delete payload.code;
            delete payload.tamCode;
            delete payload.departmentId;
            delete payload.positionId;
            delete payload.status;
        }

        if (payload.email) {
            const exitedEmployee = await EmployeesModel.findOne({ email: payload.email, _id: { $ne: id } });
            if (exitedEmployee) {
                throw new ApiError(400, 'Email của nhân viên đã tồn tại');
            }
        }

        if (payload.code) {
            const exitedEmployee = await EmployeesModel.findOne({ code: payload.code, _id: { $ne: id } });
            if (exitedEmployee) {
                throw new ApiError(400, 'Mã của nhân viên đã tồn tại');
            }
        }

        if (payload.phone) {
            const exitedEmployee = await EmployeesModel.findOne({ phone: payload.phone, _id: { $ne: id } });
            if (exitedEmployee) {
                throw new ApiError(400, 'Số điện thoại của nhân viên đã tồn tại');
            }
        }

        const employee = await EmployeesModel.findByIdAndUpdate(id, payload, { new: true });
        if (!employee) {
            throw new ApiError(400, 'Nhân viên không tồn tại');
        }

        return {
            success: true,
            message: 'Cập nhật thông tin nhân viên thành công',
            data: employee,
        };
    }

    public async deleteEmployee(id: string, userContext: IUserContext): Promise<IApiResponse<IEmployees>> {
        if (userContext && userContext.roles === UserRoleDefined.User) {
            if (String(id) !== String(userContext.user?.employeeId)) {
                throw new ApiError(403, 'Bạn không có quyền xóa thông tin nhân viên khác');
            }
        }

        const employee = await EmployeesModel.findByIdAndDelete(id);
        if (!employee) {
            throw new ApiError(400, 'Nhân viên không tồn tại');
        }

        try {
            await accountService.deleteAccountByEmployee(id);
        } catch (error) {
            // Nếu không tìm thấy account thì cũng không sao, vẫn tiếp tục thành công xóa employee
        }

        return {
            success: true,
            message: 'Xóa nhân viên thành công',
            data: employee,
        };
    }
}

import { catchAsync } from '@common/utils/catchAsync';
import { Request, Response } from 'express';
import { AttendancesService } from './attendances.service';
import {
    IAttendanceAccessControllerEvent,
    IAttendanceFromEventLogJSON,
    IAttendancesFilter,
} from '@common/interfaces/attendances.interface';
