    const result = await checkinService.createSchedule(req.body, req.users);
    res.status(201).json(result);
});

export const updateSchedule = catchAsync(async (req: Request, res: Response) => {
    const { id } = req.params;
    const result = await checkinService.updateSchedule(String(id), req.body, req.users);
    res.status(200).json(result);
});

export const deleteSchedule = catchAsync(async (req: Request, res: Response) => {
    const { id } = req.params;
    const result = await checkinService.deleteSchedule(String(id), req.users);
    res.status(200).json(result);
});

export const getSchedules = catchAsync(async (req: Request, res: Response) => {
    const { employeeId } = req.query;
    const result = await checkinService.getSchedules(req.users, employeeId as string);
    res.status(200).json(result);
});

// --- Checkin ---
export const createAbnormalCheckin = catchAsync(async (req: Request, res: Response) => {
    const result = await checkinService.createAbnormalCheckin(req.body, req.users);
    res.status(201).json(result);
});

export const updateAbnormalCheckin = catchAsync(async (req: Request, res: Response) => {
    const { id } = req.params;
    const result = await checkinService.updateAbnormalCheckin(String(id), req.body, req.users);
    res.status(200).json(result);
});

export const deleteAbnormalCheckin = catchAsync(async (req: Request, res: Response) => {
    const { id } = req.params;
    const result = await checkinService.deleteAbnormalCheckin(String(id), req.users);
    res.status(200).json(result);
});

export const confirmCheckin = catchAsync(async (req: Request, res: Response) => {
    const { id } = req.params;
    const { confirmed } = req.body;

    const result = await checkinService.confirmCheckin(String(id), confirmed, req.users);
    res.status(200).json(result);
