export const getCheckins = catchAsync(async (req: Request, res: Response) => {
    const { employeeId, date } = req.query;
    const result = await checkinService.getCheckins(req.users, employeeId as string, date as string);
    res.status(200).json(result);
});

import { IApiResponse, QueryFilter } from '@common/interfaces/response.interface';
import CheckinScheduleModel from './checkin-schedule.model';
import CheckinModel from './checkin.model';
import { ApiError } from '@common/utils/ApiError';
import { ICheckin, ICheckinPayload, ICheckinSchedule } from '@common/interfaces/checkin.interface';
import { IUserContext } from '@common/helpers/permission.helper';
import { ICheckinStatus, ICheckinType } from '@common/utils/enum';
import moment from 'moment-timezone';
import { Types } from 'mongoose';
import '@modules/employees/employees.model';

export class CheckinService {
    // --- Schedule Logic ---
    private validateCreatorInParticipants(creatorId: string | Types.ObjectId, participantIds: (string | Types.ObjectId)[]) {
        const isParticipant = participantIds.some(pid => String(pid) === String(creatorId));
        if (!isParticipant) {
            throw new ApiError(400, 'Người tạo buổi checkin phải là 1 trong 2 người tham gia');
        }
    }

    public async createSchedule(payload: ICheckinPayload, userContext: IUserContext): Promise<IApiResponse<ICheckinSchedule>> {
        const creatorId = userContext.user?.employeeId;
        if (!creatorId) throw new ApiError(401, 'Không tìm thấy thông tin nhân viên');

        if (payload.participantIds) {
            this.validateCreatorInParticipants(creatorId, payload.participantIds);
        }

        const schedule = await CheckinScheduleModel.create({
            ...payload,
            creatorId: new Types.ObjectId(String(creatorId)),
        });

        // Tự động kích hoạt nếu trùng ngày hiện tại
        const today = moment().tz('Asia/Ho_Chi_Minh');
        if (schedule.dayOfWeek === today.day()) {
            const checkinData = this.mapScheduleToCheckin(schedule, today.startOf('day').toDate());
            await CheckinModel.create(checkinData);
        }

        return {
            success: true,
            message: 'Tạo lịch checkin hàng tuần thành công',
            data: schedule,
        };
    }

    private mapScheduleToCheckin(schedule: ICheckinSchedule, date: Date) {
        return {
            scheduleId: schedule._id,
            creatorId: schedule.creatorId,
            participantIds: schedule.participantIds,
            checkinDate: date,
            startTime: schedule.startTime,
            type: ICheckinType.WEEKLY,
            status: ICheckinStatus.PENDING,
            confirmations: schedule.participantIds.map(pid => ({
                employeeId: pid,
                confirmed: null
            })),
            notified: false,
            startNotified: false
        };
    }

    public async updateSchedule(id: string, payload: ICheckinPayload, userContext: IUserContext): Promise<IApiResponse<ICheckinSchedule>> {
        const schedule = await CheckinScheduleModel.findById(id);
        if (!schedule) throw new ApiError(404, 'Không tìm thấy lịch checkin');

        const currentEmployeeId = userContext.user?.employeeId;
        if (!currentEmployeeId || String(schedule.creatorId) !== String(currentEmployeeId)) {
            throw new ApiError(403, 'Bạn không có quyền sửa lịch checkin của người khác');
        }

        if (payload.participantIds) {
            this.validateCreatorInParticipants(schedule.creatorId, payload.participantIds);
        }

        Object.assign(schedule, payload);
        await schedule.save();

        // --- Đồng bộ buổi checkin hôm nay ---
        const today = moment().tz('Asia/Ho_Chi_Minh');
        const checkinDate = today.startOf('day').toDate();

        if (schedule.dayOfWeek === today.day()) {
            // Nếu là lịch hôm nay: Cập nhật buổi PENDING hiện có hoặc tạo mới nếu chưa có
            const existingCheckin = await CheckinModel.findOne({
                scheduleId: schedule._id,
                checkinDate,
                status: ICheckinStatus.PENDING
            });

            if (existingCheckin) {
                existingCheckin.startTime = schedule.startTime;
                existingCheckin.participantIds = schedule.participantIds;
                existingCheckin.confirmations = schedule.participantIds.map(pid => ({
                    employeeId: pid,
                    confirmed: null
                }));
                await existingCheckin.save();
            } else {
                const checkinData = this.mapScheduleToCheckin(schedule, checkinDate);
                await CheckinModel.create(checkinData);
            }
        } else {
            // Nếu đổi lịch sang ngày khác: Xóa buổi PENDING của hôm nay nếu có
            await CheckinModel.findOneAndDelete({
                scheduleId: schedule._id,
                checkinDate,
                status: ICheckinStatus.PENDING
            });
        }

        return {
            success: true,
            message: 'Cập nhật lịch checkin thành công và đồng bộ dữ liệu hôm nay',
            data: schedule,
        };
    }

    public async deleteSchedule(id: string, userContext: IUserContext): Promise<IApiResponse<null>> {
        const schedule = await CheckinScheduleModel.findById(id);
        if (!schedule) throw new ApiError(404, 'Không tìm thấy lịch checkin');

        const currentEmployeeId = userContext.user?.employeeId;
        if (!currentEmployeeId || String(schedule.creatorId) !== String(currentEmployeeId)) {
            throw new ApiError(403, 'Bạn không có quyền xóa lịch checkin của người khác');
        }

        await CheckinScheduleModel.findByIdAndDelete(id);

        return {
            success: true,
            message: 'Xóa lịch checkin thành công',
            data: null,
        };
    }

    // --- Abnormal Checkin Logic ---

    private validateAbnormalTime(checkinDate: Date | string, startTime: string) {
        const hours = parseInt(startTime.substring(0, 2));
        const minutes = parseInt(startTime.slice(-2));
        const checkinTime = moment(checkinDate).tz('Asia/Ho_Chi_Minh').startOf('day')
            .set({ hour: hours, minute: minutes, second: 0, millisecond: 0 });
        const now = moment().tz('Asia/Ho_Chi_Minh');

        if (checkinTime.diff(now, 'minutes') < 30) {
            throw new ApiError(400, 'Lịch bất thường phải được tạo/sửa trước ít nhất 30 phút');
        }
    }

    public async createAbnormalCheckin(payload: ICheckinPayload, userContext: IUserContext): Promise<IApiResponse<ICheckin>> {
        const creatorId = userContext.user?.employeeId;
        if (!creatorId) throw new ApiError(401, 'Không tìm thấy thông tin nhân viên');

        if (payload.participantIds) {
            this.validateCreatorInParticipants(creatorId, payload.participantIds);
        }

        this.validateAbnormalTime(payload.checkinDate!, payload.startTime!);

        const confirmations = payload.participantIds!.map(id => ({
            employeeId: new Types.ObjectId(id),
            confirmed: null
        }));

        const checkin = await CheckinModel.create({
            ...payload,
            creatorId: new Types.ObjectId(String(creatorId)),
            type: ICheckinType.ABNORMAL,
            status: ICheckinStatus.PENDING,
            confirmations,
            notified: false,
            startNotified: false
        });

        return {
            success: true,
            message: 'Tạo buổi checkin bất thường thành công',
            data: checkin,
        };
    }

    public async updateAbnormalCheckin(id: string, payload: ICheckinPayload, userContext: IUserContext): Promise<IApiResponse<ICheckin>> {
        const checkin = await CheckinModel.findById(id);
        if (!checkin) throw new ApiError(404, 'Không tìm thấy buổi checkin');

        if (checkin.type !== ICheckinType.ABNORMAL) {
            throw new ApiError(400, 'Chỉ có thể sửa đổi buổi checkin bất thường');
        }

        const currentEmployeeId = userContext.user?.employeeId;
        if (!currentEmployeeId || String(checkin.creatorId) !== String(currentEmployeeId)) {
            throw new ApiError(403, 'Bạn không có quyền sửa buổi checkin của người khác');
        }

        if (payload.participantIds) {
            this.validateCreatorInParticipants(checkin.creatorId, payload.participantIds);
        }

        const now = moment().tz('Asia/Ho_Chi_Minh');
        const hours = parseInt(checkin.startTime.substring(0, 2));
        const minutes = parseInt(checkin.startTime.slice(-2));
        const originalTime = moment(checkin.checkinDate).tz('Asia/Ho_Chi_Minh').startOf('day')
            .set({ hour: hours, minute: minutes, second: 0, millisecond: 0 });

        if (now.isAfter(originalTime)) {
            throw new ApiError(400, 'Không thể sửa buổi checkin đã qua giờ bắt đầu');
        }

        const newDate = payload.checkinDate || checkin.checkinDate;
        const newStartTime = payload.startTime || checkin.startTime;
        this.validateAbnormalTime(newDate, newStartTime);

        if (payload.participantIds) {
            checkin.participantIds = payload.participantIds.map(pid => new Types.ObjectId(pid));
            checkin.confirmations = payload.participantIds.map(id => ({
                employeeId: new Types.ObjectId(id),
                confirmed: null
            }));
        }

        if (payload.checkinDate) checkin.checkinDate = new Date(payload.checkinDate);
        if (payload.startTime) checkin.startTime = payload.startTime;

        await checkin.save();

        return {
            success: true,
            message: 'Cập nhật buổi checkin thành công',
            data: checkin,
        };
    }

    public async deleteAbnormalCheckin(id: string, userContext: IUserContext): Promise<IApiResponse<null>> {
        const checkin = await CheckinModel.findById(id);
        if (!checkin) throw new ApiError(404, 'Không tìm thấy buổi checkin');

        const currentEmployeeId = userContext.user?.employeeId;
        if (!currentEmployeeId || String(checkin.creatorId) !== String(currentEmployeeId)) {
            throw new ApiError(403, 'Bạn không có quyền xóa buổi checkin của người khác');
        }

        const now = moment().tz('Asia/Ho_Chi_Minh');
        const hours = parseInt(checkin.startTime.substring(0, 2));
        const minutes = parseInt(checkin.startTime.slice(-2));
        const startTime = moment(checkin.checkinDate).tz('Asia/Ho_Chi_Minh').startOf('day')
            .set({ hour: hours, minute: minutes, second: 0, millisecond: 0 });

        if (now.isAfter(startTime)) {
            throw new ApiError(400, 'Không thể xóa buổi checkin đã qua giờ bắt đầu');
        }

        await CheckinModel.findByIdAndDelete(id);

        return {
            success: true,
            message: 'Xóa buổi checkin thành công',
            data: null,
        };
    }

    // --- Interaction Logic ---

    public async confirmCheckin(id: string, confirmed: boolean, userContext: IUserContext): Promise<IApiResponse<ICheckin>> {
        const employeeId = userContext.user?.employeeId;
        if (!employeeId) throw new ApiError(401, 'Không tìm thấy thông tin nhân viên');

        const checkin = await CheckinModel.findById(id);
        if (!checkin) throw new ApiError(404, 'Không tìm thấy buổi checkin');

        if (checkin.status !== ICheckinStatus.ONGOING) {
            throw new ApiError(400, 'Chỉ có thể xác nhận khi buổi checkin đang diễn ra (ongoing)');
        }

        const confirmation = checkin.confirmations.find(c => String(c.employeeId) === String(employeeId));
        if (!confirmation) {
            throw new ApiError(403, 'Bạn không phải là người tham gia buổi checkin này');
        }

        confirmation.confirmed = confirmed;
        confirmation.confirmedAt = new Date();

        // Check overall status
        const allResponded = checkin.confirmations.every(c => c.confirmed !== null);
        const allConfirmed = checkin.confirmations.every(c => c.confirmed === true);

        if (allResponded) {
            if (allConfirmed) {
                checkin.status = ICheckinStatus.SUCCESS;
            } else {
                checkin.status = ICheckinStatus.CANCELED;
            }
        } else if (confirmed === false) {
            // If anyone refuses, it's canceled immediately
            checkin.status = ICheckinStatus.CANCELED;
        }

        await checkin.save();

        return {
            success: true,
            message: confirmed ? 'Xác thực tham gia thành công' : 'Đã từ chối tham gia',
            data: checkin,
        };
    }

    public async getCheckins(userContext: IUserContext, filterEmployeeId?: string, filterDate?: string): Promise<IApiResponse<ICheckin[]>> {
        const targetId = filterEmployeeId || userContext.user?.employeeId;
        const query: QueryFilter<ICheckinPayload> = {
            participantIds: new Types.ObjectId(String(targetId))
        };

        if (filterDate) {
            query.checkinDate = moment(filterDate).tz('Asia/Ho_Chi_Minh').startOf('day').toDate();
        }

        const checkins = await CheckinModel.find(query).sort({ checkinDate: -1, startTime: -1 });

        return {
            success: true,
            data: checkins
        };
    }

    public async getSchedules(userContext: IUserContext, filterEmployeeId?: string): Promise<IApiResponse<ICheckinSchedule[]>> {
        const targetId = filterEmployeeId || userContext.user?.employeeId;
        const schedules = await CheckinScheduleModel.find({
            participantIds: new Types.ObjectId(String(targetId))
        }).populate('creatorId participantIds');

        return {
            success: true,
            data: schedules
        };
    }
}

import { catchAsync } from '@common/utils/catchAsync';
import { Request, Response } from 'express';
import { OKRService } from './okrs.service';
import { IOKRFilter, IOKRRankingFilter } from '@common/interfaces/okrs.interface';
import { IOKRStatus } from '@common/utils/enum';
import { Types } from 'mongoose';

const okrService = new OKRService();

export const createOKR = catchAsync(async (req: Request, res: Response) => {
    const okr = await okrService.createOKR(req.body, req.users);
    res.status(200).json(okr);
});

export const getOKRByFilter = catchAsync(async (req: Request, res: Response) => {
    const filter: IOKRFilter = {
        status: req.query.status ? (String(req.query.status) as IOKRStatus) : undefined,
        name: req.query.name ? String(req.query.name) : undefined,
        employeeId: req.query.employeeId ? new Types.ObjectId(String(req.query.employeeId)) : undefined,
        departmentId: req.query.departmentId ? new Types.ObjectId(String(req.query.departmentId)) : undefined,
        quarter: req.query.quarter ? parseInt(String(req.query.quarter), 10) : undefined,
