import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import { ApiError } from '@common/utils/ApiError';
import { ILeaveRequestsStatus, ILeaveSession, UserRoleDefined } from '@common/utils/enum';
import { QueryFilter } from 'mongoose';
import {
    ILeaveRequests,
    ILeaveRequestsApprovalPayload,
    ILeaveRequestsFilter,
    ILeaveRequestsFilterGetOne,
    ILeaveRequestsPayload,
    ILeaveRequestsUpdate,
} from '@common/interfaces/leaveRequests.interface';
import LeaveRequestsModel from './leaveRequests.model';
import LeaveTypeModel from '@modules/leaveTypes/leaveType.model';
import EmployeesModel from '@modules/employees/employees.model';
import DepartmentModel from '@modules/departments/department.model';
import { LeaveBalancesService } from '@modules/leaveBalances/leaveBalances.service';
import PositionModel from '@modules/positions/position.model';
import AccountModel from '@modules/accounts/accounts.model';
import AccountRoleModel from '@modules/accountRoles/accountRole.model';
import RoleModel from '@modules/roles/role.model';
import { socketService } from '@socket/socket.service';
import { EVENT_NOTI_LEAVE_REQUEST } from '@common/utils/enum';

const leaveBalancesService = new LeaveBalancesService();
const AUTO_APPROVE_POSITIONS = ['CEO', 'CCO', 'CIO', 'CTO', 'CFO'];

export class LeaveRequestsService {
    /**
     * Tính tổng số ngày nghỉ dựa trên startDate, endDate, session
     */
    private calculateTotalDays(startDate: Date, endDate: Date, session: ILeaveSession): number {
        const start = new Date(startDate);
        const end = new Date(endDate);
        start.setHours(0, 0, 0, 0);
        end.setHours(0, 0, 0, 0);

        let totalDays = 0;
        const current = new Date(start);

        while (current <= end) {
            const dayOfWeek = current.getDay();
            if (dayOfWeek !== 0) { // Loại trừ không tính Chủ nhật vào lịch nghỉ phép (0)
                totalDays += 1;
            }
            current.setDate(current.getDate() + 1);
        }

        if (totalDays <= 0) return 0;

        if (session === ILeaveSession.MORNING || session === ILeaveSession.AFTERNOON) {
            return totalDays * 0.5;
        }
        return totalDays;
    }

    /**
     * Tự động xác định approver dựa trên employee → department → managerId
     */
    private async resolveApprover(employeeId: string): Promise<string | null> {
        const employee = await EmployeesModel.findById(employeeId);
        if (!employee || !employee.departmentId) return null;

        const department = await DepartmentModel.findById(employee.departmentId);
        if (!department || !department.managerId) return null;

        // Nếu managerId chính là bản thân → tìm department cha
        if (department.managerId.toString() === employeeId && department.parentId) {
            const parentDept = await DepartmentModel.findById(department.parentId);
            if (parentDept && parentDept.managerId) {
                return parentDept.managerId.toString();
            }
        }

        return department.managerId.toString();
    }

    public async createLeaveRequests(
        payload: ILeaveRequestsPayload,
        requestEmployeeId?: string,
    ): Promise<IApiResponse<ILeaveRequests>> {
        const session = payload.session || ILeaveSession.FULL_DAY;
        const totalDays = this.calculateTotalDays(payload.startDate, payload.endDate, session);

        if (totalDays <= 0) {
            throw new ApiError(400, 'Ngày kết thúc phải sau ngày bắt đầu');
        }

        // Lấy thông tin loại nghỉ phép
        const leaveType = await LeaveTypeModel.findById(payload.leaveTypeId);
        if (!leaveType) {
            throw new ApiError(404, 'Loại nghỉ phép không tồn tại');
        }

        // Lấy dept cho nhân viên
        const employee = await EmployeesModel.findById(payload.employeeId);
        const departmentId = employee?.departmentId;

        // KIỂM TRA TRÙNG LỊCH NGHỈ
        const overlappingRequests = await LeaveRequestsModel.find({
            employeeId: payload.employeeId,
            status: { $nin: [ILeaveRequestsStatus.REJECTED, ILeaveRequestsStatus.CANCELLED] },
            $or: [
                { startDate: { $lte: payload.endDate }, endDate: { $gte: payload.startDate } }
            ]
        });

        if (overlappingRequests.length > 0) {
            throw new ApiError(400, 'Bạn đã có đơn xin nghỉ phép trong khoảng thời gian này');
        }

        // Tự động xác định approver (người quản lý)
        const managerApproverEmployeeId = await this.resolveApprover(payload.employeeId.toString());

        // KIỂM TRA TỰ ĐỘNG DUYỆT
        let status = ILeaveRequestsStatus.PENDING;
        if (employee?.positionId) {
            const position = await PositionModel.findById(employee.positionId);
            if (position && AUTO_APPROVE_POSITIONS.includes(position.name)) {
                status = ILeaveRequestsStatus.LEVEL1_APPROVED;
            }
        }

        // TÍNH TOÁN PHÂN TÁCH PHÉP CÓ LƯƠNG / KHÔNG LƯƠNG
        let paidDays = 0;
        let unpaidDays = totalDays;

        if (leaveType.code === 'AL') {
            const year = new Date(payload.startDate).getFullYear();
            const balance = await leaveBalancesService.getOrCreateBalance(
                payload.employeeId.toString(),
                year,
            );
            const available =
                balance.totalEntitled + balance.carryOver - balance.totalUsed - balance.totalPending;

            if (totalDays > available) {
                throw new ApiError(400, `Quỹ phép năm không đủ. Bạn chỉ còn ${available} ngày phép khả dụng.`);
            }

            paidDays = totalDays;
            unpaidDays = 0;

            // Tạm giữ ngày phép trong totalPending
            balance.totalPending += totalDays;
            await balance.save();
        } else {
            // Các loại khác (UL, WFH, SL, BT...) không sử dụng quỹ phép
            paidDays = leaveType.isPaid ? totalDays : 0;
            unpaidDays = leaveType.isPaid ? 0 : totalDays;
        }

        const newLeaveRequest = await LeaveRequestsModel.create({
            ...payload,
            session,
            totalDays,
            paidDays,
            unpaidDays,
            departmentId,
            level1ApproverEmployeeId: status === ILeaveRequestsStatus.LEVEL1_APPROVED
                ? payload.employeeId.toString()
                : managerApproverEmployeeId,
            level1ApprovedAt: status === ILeaveRequestsStatus.LEVEL1_APPROVED ? new Date() : undefined,
            status,
        });

        // GỬI THÔNG BÁO SOCKET
        const creatorName = employee?.fullName || 'Một nhân viên';
        if (status === ILeaveRequestsStatus.PENDING && managerApproverEmployeeId) {
            // Thông báo cho Quản lý có đơn mới
            const managerAccountId = await this.getAccountIdByEmployeeId(managerApproverEmployeeId);
            if (managerAccountId) {
                socketService.sendNotification(managerAccountId, EVENT_NOTI_LEAVE_REQUEST, {
                    message: `${creatorName} đã tạo đơn xin nghỉ phép mới chờ bạn duyệt.`,
                    requestId: newLeaveRequest._id,
                    status: newLeaveRequest.status,
                });
            }
        } else if (status === ILeaveRequestsStatus.LEVEL1_APPROVED) {
            // Nếu tự động duyệt cấp 1 (CEO...), thông báo cho HR
            const hrAccountIds = await this.getAccountIdsByHRRole();
            hrAccountIds.forEach((accountId) => {
                socketService.sendNotification(accountId, EVENT_NOTI_LEAVE_REQUEST, {
                    message: `${creatorName} đã tạo đơn nghỉ phép (đã tự động duyệt cấp 1), chờ HR duyệt.`,
                    requestId: newLeaveRequest._id,
                    status: newLeaveRequest.status,
                });
            });
        }

        return {
            success: true,
            message: 'Tạo yêu cầu nghỉ phép thành công',
            data: newLeaveRequest,
        };
    }

    public async getOneLeaveRequests(
        filter: ILeaveRequestsFilterGetOne,
    ): Promise<IApiResponse<ILeaveRequests>> {
        const record = await LeaveRequestsModel.findOne(filter);
        if (!record) {
            return {
                success: false,
                message: 'Không tìm thấy yêu cầu nghỉ phép',
                data: null as unknown as ILeaveRequests,
            };
        }
        return {
            success: true,
            message: 'Đã thấy yêu cầu nghỉ phép',
            data: record,
        };
    }

    public async getLeaveRequestsByFilter(
        filter: ILeaveRequestsFilter,
        userRole?: string,
        requestingEmployeeId?: string,
    ): Promise<IPaginatedResponse<ILeaveRequests>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const query: any = {};

        // === PHÂN QUYỀN HIỂN THỊ (VISIBILITY RULES) ===
        if (userRole === UserRoleDefined.HR) {
            // HR thấy mọi phòng ban nhưng KHÔNG thấy đơn PENDING
            query.status = { $ne: ILeaveRequestsStatus.PENDING };
        } else if (
            userRole !== UserRoleDefined.Admin &&
            userRole !== UserRoleDefined.SuperAdmin
        ) {
            // Nhân viên & Quản lý chỉ thấy đơn của phòng ban mình
            const requester = await EmployeesModel.findById(requestingEmployeeId);
            if (requester?.departmentId) {
                query.departmentId = requester.departmentId;
            } else {
                // Nếu chưa gán phòng ban, chỉ thấy chính mình
                query.employeeId = requestingEmployeeId;
            }
        }

        // === CÁC FILTER TỪ CLIENT (GỘP VÀO TRUY VẤN PHÂN QUYỀN) ===
        if (filter.evidence) {
            const evidence = filter.evidence.normalize('NFC');
            query.evidence = {
                $regex: `.*${evidence}.*`,
                $options: 'i',
            };
        }

        const andQuery: any[] = [];
        if (filter.startDate) {
            andQuery.push({
                $expr: {
                    $gte: [{ $toDate: '$startDate' }, filter.startDate],
                },
            });
        }
        if (filter.endDate) {
            andQuery.push({
                $expr: {
                    $lte: [{ $toDate: '$endDate' }, filter.endDate],
                },
            });
        }

        if (andQuery.length > 0) {
            query.$and = andQuery;
        }

        if (filter.totalDays) {
            query.totalDays = filter.totalDays;
        }
        // Ghi đè status nếu filter truyền lên, nhưng vẫn phải tuân thủ quy tắc HR (không xem được pending)
        if (filter.status) {
            if (userRole === UserRoleDefined.HR && filter.status === ILeaveRequestsStatus.PENDING) {
                // HR cố tình tìm pending -> Trả về kết quả rỗng hoặc chuyển sang đơn hợp lệ
                query.status = { $in: [] };
            } else {
                query.status = filter.status;
            }
        }
        if (filter.employeeId) {
            query.employeeId = filter.employeeId;
        }
        if (filter.leaveTypeId) {
            query.leaveTypeId = filter.leaveTypeId;
        }
        if (filter.session) {
            query.session = filter.session;
        }
        // Cho phép search theo departmentId nếu là Admin/HR, nếu là Manager thì query.departmentId đã bị fix ở trên
        if (filter.departmentId && !query.departmentId) {
            query.departmentId = filter.departmentId;
        }

        const aggregateQuery = [{ $match: query }];
        const [records, docCounter] = await Promise.all([
            LeaveRequestsModel.aggregate(aggregateQuery)
                .sort({ createdAt: -1 })
                .skip((page - 1) * limit)
                .limit(limit),
            LeaveRequestsModel.aggregate([...aggregateQuery, { $count: 'count' }]),
        ]);
        const count = docCounter[0]?.count || 0;

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách yêu cầu nghỉ phép thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async getLeaveRequestsById(id: string): Promise<IApiResponse<ILeaveRequests>> {
        const record = await LeaveRequestsModel.findById(id);
        if (!record) {
            throw new ApiError(404, 'Không tìm thấy yêu cầu nghỉ phép này');
        }
        return {
            success: true,
            message: 'Đã thấy yêu cầu nghỉ phép',
            data: record,
        };
    }

    public async updateLeaveRequestsById(
        id: string,
        payload: ILeaveRequestsUpdate,
    ): Promise<IApiResponse<ILeaveRequests>> {
        const leaveRequest = await LeaveRequestsModel.findById(id);
        if (!leaveRequest) {
            throw new ApiError(400, 'Yêu cầu nghỉ phép không tồn tại');
        }

        // Chỉ cho phép sửa khi status = PENDING
        if (leaveRequest.status !== ILeaveRequestsStatus.PENDING) {
            throw new ApiError(400, 'Chỉ có thể sửa yêu cầu nghỉ phép đang chờ duyệt');
        }

        const updateData: Record<string, unknown> = { ...payload };
        const startDate = payload.startDate || leaveRequest.startDate;
        const endDate = payload.endDate || leaveRequest.endDate;
        const session = payload.session || leaveRequest.session;

        // KIỂM TRA TRÙNG LỊCH NGHỈ (BỎ QUA CHÍNH NÓ)
        const overlappingRequests = await LeaveRequestsModel.find({
            _id: { $ne: id },
            employeeId: leaveRequest.employeeId,
            status: { $nin: [ILeaveRequestsStatus.REJECTED, ILeaveRequestsStatus.CANCELLED] },
            $or: [
                { startDate: { $lte: endDate }, endDate: { $gte: startDate } }
            ]
        });

        if (overlappingRequests.length > 0) {
            throw new ApiError(400, 'Bạn đã có đơn xin nghỉ phép khác trong khoảng thời gian này');
        }

        if (payload.startDate || payload.endDate || payload.session || payload.leaveTypeId) {
            const newTotalDays = this.calculateTotalDays(startDate, endDate, session);
            updateData.totalDays = newTotalDays;

            const oldLeaveType = await LeaveTypeModel.findById(leaveRequest.leaveTypeId);
            const newLeaveType = await LeaveTypeModel.findById(payload.leaveTypeId || leaveRequest.leaveTypeId);

            if (newLeaveType?.code === 'AL') {
                const year = new Date(startDate).getFullYear();
                const balance = await leaveBalancesService.getOrCreateBalance(
                    leaveRequest.employeeId.toString(),
                    year,
                );

                // 1. Tạm thời hoàn trả số ngày cũ (nếu đơn cũ cũng là AL) để tính toán số dư thực tế
                if (oldLeaveType?.code === 'AL') {
                    balance.totalPending = Math.max(0, balance.totalPending - leaveRequest.paidDays);
                }

                // 2. Kiểm tra quỹ phép mới
                const available = balance.totalEntitled + balance.carryOver - balance.totalUsed - balance.totalPending;
                if (newTotalDays > available) {
                    throw new ApiError(400, `Quỹ phép năm không đủ để cập nhật. Bạn chỉ còn ${available} ngày phép khả dụng.`);
                }

                updateData.paidDays = newTotalDays;
                updateData.unpaidDays = 0;

                // 3. Cập nhật lại totalPending mới
                balance.totalPending += newTotalDays;
                await balance.save();
            } else {
                // Nếu đơn mới KHÔNG PHẢI AL
                updateData.paidDays = newLeaveType?.isPaid ? newTotalDays : 0;
                updateData.unpaidDays = newLeaveType?.isPaid ? 0 : newTotalDays;

                // Nếu đơn CŨ là AL, ta phải hoàn trả quỹ phép
                if (oldLeaveType?.code === 'AL') {
                    const year = new Date(leaveRequest.startDate).getFullYear();
                    const balance = await leaveBalancesService.getOrCreateBalance(
                        leaveRequest.employeeId.toString(),
                        year,
                    );
                    balance.totalPending = Math.max(0, balance.totalPending - leaveRequest.paidDays);
                    await balance.save();
                }
            }
        }

        const updated = await LeaveRequestsModel.findByIdAndUpdate(id, updateData, {
            returnDocument: 'after',
        });

        return {
            success: true,
            message: 'Cập nhật thông tin yêu cầu nghỉ phép thành công',
            data: updated as ILeaveRequests,
        };
    }

    public async deleteLeaveRequestsById(id: string): Promise<IApiResponse<ILeaveRequests>> {
        const leaveRequest = await LeaveRequestsModel.findById(id);
        if (!leaveRequest) {
            throw new ApiError(400, 'Yêu cầu nghỉ phép không tồn tại');
        }

        // Hoàn phép nếu đang pending và loại nghỉ có trừ phép
        if (
            leaveRequest.status === ILeaveRequestsStatus.PENDING ||
            leaveRequest.status === ILeaveRequestsStatus.LEVEL1_APPROVED
        ) {
            const leaveType = await LeaveTypeModel.findById(leaveRequest.leaveTypeId);
            if (leaveType?.code === 'AL' && leaveRequest.paidDays > 0) {
                const year = new Date(leaveRequest.startDate).getFullYear();
                await leaveBalancesService.refundBalance(
                    leaveRequest.employeeId.toString(),
                    year,
                    leaveRequest.paidDays,
                );
            }
        }

        await LeaveRequestsModel.findByIdAndDelete(id);
        return {
            success: true,
            message: 'Xóa yêu cầu nghỉ phép thành công',
            data: leaveRequest,
        };
    }

    /**
     * Duyệt yêu cầu nghỉ phép - 2 cấp
     * Cấp 1: Manager/Director/SuperAdmin duyệt: PENDING → LEVEL1_APPROVED | REJECTED
     * Cấp 2: HR duyệt: LEVEL1_APPROVED → HR_APPROVED | REJECTED
     */
    public async approveLeaveRequestsById(
        id: string,
        approverEmployeeId: string | undefined,
        role: string,
        payload: ILeaveRequestsApprovalPayload,
    ): Promise<IApiResponse<ILeaveRequests>> {
        const leaveRequest = await LeaveRequestsModel.findById(id);
        if (!leaveRequest) {
            throw new ApiError(404, 'Không tìm thấy yêu cầu nghỉ phép');
        }

        const employee = await EmployeesModel.findById(leaveRequest.employeeId);
        const updateData: Record<string, unknown> = {};
        const now = new Date();

        // === TRƯỜNG HỢP 1: QUẢN LÝ (CẤP 1) DUYỆT ===
        if (approverEmployeeId === leaveRequest.level1ApproverEmployeeId?.toString()) {
            if (leaveRequest.status !== ILeaveRequestsStatus.PENDING) {
                throw new ApiError(400, 'Chỉ có thể duyệt cấp 1 khi đơn đang ở trạng thái Chờ duyệt (Pending)');
            }

            if (payload.status === ILeaveRequestsStatus.LEVEL1_APPROVED) {
                updateData.status = ILeaveRequestsStatus.LEVEL1_APPROVED;
                updateData.level1ApprovedAt = now;

                // Thông báo cho HR có đơn mới cần duyệt cuối
                const hrAccountIds = await this.getAccountIdsByHRRole();
                hrAccountIds.forEach((accountId) => {
                    socketService.sendNotification(accountId, EVENT_NOTI_LEAVE_REQUEST, {
                        message: `Có đơn nghỉ phép của ${employee?.fullName} đã được Quản lý duyệt, chờ HR phê duyệt cuối.`,
                        requestId: leaveRequest._id,
                        status: ILeaveRequestsStatus.LEVEL1_APPROVED,
                    });
                });
            } else if (payload.status === ILeaveRequestsStatus.REJECTED) {
                updateData.status = ILeaveRequestsStatus.REJECTED;

                // Hoàn phép (chỉ khi là AL)
                const leaveType = await LeaveTypeModel.findById(leaveRequest.leaveTypeId);
                if (leaveType?.code === 'AL' && leaveRequest.paidDays > 0) {
                    const year = new Date(leaveRequest.startDate).getFullYear();
                    await leaveBalancesService.refundBalance(leaveRequest.employeeId.toString(), year, leaveRequest.paidDays);
                }
            } else {
                throw new ApiError(400, 'Trạng thái duyệt cấp 1 không hợp lệ');
            }

            // Thông báo kết quả cho Nhân viên
            const creatorAccountId = await this.getAccountIdByEmployeeId(leaveRequest.employeeId.toString());
            if (creatorAccountId) {
                const statusText = payload.status === ILeaveRequestsStatus.LEVEL1_APPROVED ? 'được Quản lý duyệt' : 'bị Quản lý từ chối';
                socketService.sendNotification(creatorAccountId, EVENT_NOTI_LEAVE_REQUEST, {
                    message: `Đơn nghỉ phép của bạn đã ${statusText}.`,
                    requestId: leaveRequest._id,
                    status: updateData.status,
                });
            }
        }
        // === TRƯỜNG HỢP 2: HR (CẤP 2) DUYỆT ===
        else if (role === UserRoleDefined.HR) {
            if (leaveRequest.status !== ILeaveRequestsStatus.LEVEL1_APPROVED) {
                throw new ApiError(400, 'HR chỉ có thể duyệt sau khi Quản lý đã duyệt (Level 1 Approved)');
            }

            if (payload.status === ILeaveRequestsStatus.HR_APPROVED) {
                updateData.status = ILeaveRequestsStatus.HR_APPROVED;
                updateData.hrApprovedAt = now;
                updateData.hrApproverEmployeeId = approverEmployeeId;

                // Trừ phép chính thức (chỉ dành cho AL)
                const leaveType = await LeaveTypeModel.findById(leaveRequest.leaveTypeId);
                if (leaveType?.code === 'AL' && leaveRequest.paidDays > 0) {
                    const year = new Date(leaveRequest.startDate).getFullYear();
                    await leaveBalancesService.deductBalance(leaveRequest.employeeId.toString(), year, leaveRequest.paidDays);
                }
            } else if (payload.status === ILeaveRequestsStatus.REJECTED) {
                updateData.status = ILeaveRequestsStatus.REJECTED;

                // Hoàn phép (chỉ dành cho AL)
                const leaveType = await LeaveTypeModel.findById(leaveRequest.leaveTypeId);
                if (leaveType?.code === 'AL' && leaveRequest.paidDays > 0) {
                    const year = new Date(leaveRequest.startDate).getFullYear();
                    await leaveBalancesService.refundBalance(leaveRequest.employeeId.toString(), year, leaveRequest.paidDays);
                }
            } else {
                throw new ApiError(400, 'Trạng thái duyệt cấp 2 không hợp lệ');
            }

            // Thông báo kết quả cuối cho Nhân viên
            const creatorAccountId = await this.getAccountIdByEmployeeId(leaveRequest.employeeId.toString());
            if (creatorAccountId) {
                const statusText = payload.status === ILeaveRequestsStatus.HR_APPROVED ? 'đã được HR phê duyệt cuối cùng' : 'đã bị HR từ chối';
                socketService.sendNotification(creatorAccountId, EVENT_NOTI_LEAVE_REQUEST, {
                    message: `Đơn nghỉ phép của bạn ${statusText}.`,
                    requestId: leaveRequest._id,
                    status: updateData.status,
                });
            }
        } else {
            throw new ApiError(403, 'Bạn không có quyền duyệt ở cấp độ này');
        }

        const updatedRequest = await LeaveRequestsModel.findByIdAndUpdate(id, updateData, { new: true });

        return {
            success: true,
            message: 'Phê duyệt yêu cầu nghỉ phép thành công',
            data: updatedRequest as ILeaveRequests,
        };
    }

    /**
     * Nhân viên hủy đơn nghỉ phép
     */
    public async cancelLeaveRequest(
        id: string,
        employeeId: string | undefined,
    ): Promise<IApiResponse<ILeaveRequests>> {
        const leaveRequest = await LeaveRequestsModel.findById(id);
        if (!leaveRequest) {
            throw new ApiError(404, 'Không tìm thấy yêu cầu nghỉ phép');
        }

        // Chỉ chủ đơn mới được hủy
        if (leaveRequest.employeeId.toString() !== employeeId) {
            throw new ApiError(403, 'Bạn không phải chủ đơn nghỉ phép này');
        }

        // Chỉ cho phép hủy khi PENDING hoặc LEVEL1_APPROVED
        if (
            leaveRequest.status !== ILeaveRequestsStatus.PENDING &&
            leaveRequest.status !== ILeaveRequestsStatus.LEVEL1_APPROVED
        ) {
            throw new ApiError(
                400,
                'Chỉ có thể hủy đơn khi đang chờ duyệt hoặc đã được quản lý duyệt',
            );
        }

        // Hoàn phép (chỉ khi là AL)
        const leaveType = await LeaveTypeModel.findById(leaveRequest.leaveTypeId);
        if (leaveType?.code === 'AL' && leaveRequest.paidDays > 0) {
            const year = new Date(leaveRequest.startDate).getFullYear();
            await leaveBalancesService.refundBalance(
                leaveRequest.employeeId.toString(),
                year,
                leaveRequest.paidDays,
            );
        }

        const updated = await LeaveRequestsModel.findByIdAndUpdate(
            id,
            { status: ILeaveRequestsStatus.CANCELLED },
            { returnDocument: 'after' },
        );

        // Thông báo cho Quản lý là đơn đã bị hủy
        const managerApproverEmployeeId = leaveRequest.level1ApproverEmployeeId;
        if (managerApproverEmployeeId) {
            const managerAccountId = await this.getAccountIdByEmployeeId(managerApproverEmployeeId.toString());
            if (managerAccountId) {
                socketService.sendNotification(managerAccountId, EVENT_NOTI_LEAVE_REQUEST, {
                    message: `Nhân viên đã hủy đơn nghỉ phép mã ${leaveRequest._id}.`,
                    requestId: leaveRequest._id,
                    status: ILeaveRequestsStatus.CANCELLED,
                });
            }
        }

        return {
            success: true,
            message: 'Hủy yêu cầu nghỉ phép thành công',
            data: updated as ILeaveRequests,
        };
    }

    /**
     * Tìm Account ID theo Employee ID
     */
    private async getAccountIdByEmployeeId(employeeId: string): Promise<string | null> {
        const account = await AccountModel.findOne({ employeeId });
        return account ? String(account._id) : null;
    }

    /**
     * Tìm tất cả Account ID có role HR
     */
    private async getAccountIdsByHRRole(): Promise<string[]> {
        const roleHR = await RoleModel.findOne({ name: UserRoleDefined.HR });
        if (!roleHR) return [];

        const accountRoles = await AccountRoleModel.find({ roleId: String(roleHR._id) });
        return accountRoles.map((ar) => String(ar.accountId));
    }
}

import { Request, Response } from 'express';
import { catchAsync } from '@common/utils/catchAsync';
import { AccountService } from '@modules/accounts/account.service';
import AccountModel from '@modules/accounts/accounts.model';
import { ApiError } from '@common/utils/ApiError';
import { comparePassword } from '@common/utils/hashPassword';
import { IAccountStatus } from '@common/utils/enum';
import { AccountRoleService } from '@modules/accountRoles/accountRole.service';
import { RoleService } from '@modules/roles/role.service';
import { generateToken, verifyToken } from '@common/utils/token';
import { EmployeesService } from '@modules/employees/employees.service';

const accountService = new AccountService();
const accountRole = new AccountRoleService();
const roleService = new RoleService();
const employeesService = new EmployeesService();

export const login = catchAsync(async (req: Request, res: Response) => {
    const employee = await employeesService.getOneEmployee({ email: req.body.email });
    let account = await AccountModel.findOne({
        $or: [{ email: req.body.email }, ...(employee.data ? [{ employeeId: employee.data._id }] : [])],
    }).select('+password');

    if (!employee.data && !account) {
        throw new ApiError(400, 'Tài khoản hoặc mật khẩu không đúng');
    }
    if (employee.data && !account) {
        account = await AccountModel.findOne({ employeeId: employee.data._id }).select('+password');
    }

    if (!account) {
        throw new ApiError(400, 'Tài khoản hoặc mật khẩu không đúng');
    }

    const isValidPassword = await comparePassword(req.body.password, account.password);
    if (!isValidPassword) {
        throw new ApiError(400, 'Tài khoản hoặc mật khẩu không đúng');
    }

    if (account.status === IAccountStatus.Inactive) {
        throw new ApiError(400, 'Tài khoản chưa được kích hoạt');
    }

    const userRole = await accountRole.getAccountRoleByAccountId(String(account._id));
    if (!userRole) {
        throw new ApiError(400, 'Tài khoản chưa có vai trò');
    }
    const role = await roleService.getRoleById(userRole.roleId);
    const accessToken = generateToken(
        {
            accountId: String(account._id),
            roleName: role.data.name,
            tokenVersion: account.tokenVersion,
        },
        '2h',
    );

    const refreshToken = generateToken(
        {
            accountId: String(account._id),
            roleName: role.data.name,
            tokenVersion: account.tokenVersion,
        },
        '30d',
    );

    const userDoc = await AccountModel.findById(account._id).populate({
        path: 'employeeId',
        populate: [{ path: 'departmentId' }, { path: 'positionId' }],
    });
    const user = userDoc.toObject();
    if (user) {
        delete (user as { password?: string }).password;
    }

    const record = {
        accessToken: accessToken,
        data: user,
        roles: role.data.name,
    };

    res.cookie('refreshToken', refreshToken, {
        httpOnly: true,
        secure: false,
        sameSite: 'strict',
        maxAge: 30 * 24 * 60 * 60 * 1000,
    });

    res.status(200).json({
        success: true,
        message: 'Đăng nhập thành công',
        data: record,
    });
});

export const refreshToken = catchAsync(async (req: Request, res: Response) => {
    const refreshTokenFromCookie = req.cookies.refreshToken;
    const decoded = verifyToken(refreshTokenFromCookie);
    const remainingSeconds = decoded.exp - Math.floor(Date.now() / 1000);
    const remainingDays = Math.ceil(remainingSeconds / (60 * 60 * 24));
    if (remainingSeconds < 0) {
        throw new ApiError(401, 'Refresh token đã hết hạn');
    }
    const account = await accountService.getAccountById(String(decoded.accountId));
    const userRole = await accountRole.getAccountRoleByAccountId(String(account.data._id));
    const role = (await roleService.getRoleById(userRole.roleId)).data;
    const accessToken = generateToken(
        {
            accountId: String(account.data._id),
            roleName: role.name,
            tokenVersion: account.data.tokenVersion,
        },
        '2h',
    );

    const refreshToken = generateToken(
        {
            accountId: String(account.data._id),
            roleName: role.name,
            tokenVersion: account.data.tokenVersion,
        },
        `${remainingDays}d`,
    );

    const userDoc = await AccountModel.findById(account.data._id).populate({
        path: 'employeeId',
        populate: [{ path: 'departmentId' }, { path: 'positionId' }],
    });
    const user = userDoc.toObject();
    if (user) {
        delete (user as { password?: string }).password;
    }

    const record = {
        accessToken: accessToken,
        data: user,
        roles: role.name,
    };

    res.cookie('refreshToken', refreshToken, {
        httpOnly: true,
        secure: false,
        sameSite: 'strict',
        maxAge: remainingDays * 24 * 60 * 60 * 1000,
    });

    res.status(200).json({
        success: true,
        message: 'Refresh token thành công',
        data: record,
    });
});

export const loginByToken = catchAsync(async (req: Request, res: Response) => {
    const authorization = req.headers.authorization;
    const token = String(authorization).split(' ')[1];
    const decoded = verifyToken(token);
    const accountDoc = await AccountModel.findById(String(decoded.accountId)).populate({
        path: 'employeeId',
        populate: [{ path: 'departmentId' }, { path: 'positionId' }],
    });

    if (accountDoc.tokenVersion !== decoded.tokenVersion) {
        throw new ApiError(401, 'Phiên đăng nhập đã hết hạn');
    }

    const userRole = await accountRole.getAccountRoleByAccountId(String(accountDoc._id));
    const role = (await roleService.getRoleById(userRole.roleId)).data;

    const user = accountDoc.toObject();
    if (user) {
        delete (user as { password?: string }).password;
    }

    const record = {
        data: user,
        roles: role.name,
    };

    res.status(200).json({
        success: true,
        message: 'Lấy thông tin người dùng thành công',
        data: record,
    });
});

