import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import { IPermissionFilter, IPermissionPayload, IPermissions } from '@common/interfaces/permissions.interface';
import PermissionModel from './permission.model';
import { ApiError } from '@common/utils/ApiError';
import mongoose, { QueryFilter, Types } from 'mongoose';
import { RedisAdapter } from '@config/redis';
import RolesModel from '@modules/roles/role.model';
import logger from '@common/utils/logger';
import { IRoles } from '@common/interfaces/roles.interface';

export class PermissionService {
    private static callingPermissionMaps = new Map<string, Promise<unknown>>();

    public async createPermission(payload: IPermissionPayload): Promise<IApiResponse<IPermissions>> {
        const session = await mongoose.startSession();
        session.startTransaction();
        try {
            const existed = await PermissionModel.findOne({ roleId: payload.roleId }).session(session);
            if (existed) {
                throw new ApiError(400, 'Quyền cho role này đã tồn tại');
            }

            const newPermission = (await PermissionModel.create([payload], { session }))[0];

            // Đồng bộ cache Redis
            const role = await RolesModel.findById(payload.roleId).session(session);
            if (role && role.name) {
                const key = RedisAdapter.genPermissionKey(role.name);
                await RedisAdapter.delete(key);
                if (payload.permissions && payload.permissions.length > 0) {
                    await RedisAdapter.sadd(key, ...payload.permissions);
                }
            }

            await session.commitTransaction();
            return {
                success: true,
                message: 'Permission created successfully',
                data: newPermission,
            };
        } catch (error) {
            await session.abortTransaction();
            throw error;
        } finally {
            session.endSession();
        }
    }

    public async getPermissionById(id: string): Promise<IApiResponse<IPermissions>> {
        const permission = await PermissionModel.findById(id).populate('roleId');
        if (!permission) {
            throw new ApiError(404, 'Không tìm thấy quyền này');
        }
        return {
            success: true,
            message: 'Đã tìm thấy quyền',
            data: permission,
        };
    }

    public async getPermissionByRoleId(roleId: string): Promise<IApiResponse<IPermissions>> {
        const permission = await PermissionModel.findOne({ roleId }).populate('roleId');
        if (!permission) {
            return {
                success: false,
                message: 'Không tìm thấy quyền cho role này',
                data: null,
            };
        }
        return {
            success: true,
            message: 'Đã tìm thấy quyền',
            data: permission,
        };
    }

    public async getPermissions(filter: IPermissionFilter): Promise<IPaginatedResponse<IPermissions>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const query: QueryFilter<IPermissions> = {};

        if (filter.roleId) {
            query.roleId = new Types.ObjectId(filter.roleId);
        }

        const [records, count] = await Promise.all([
            PermissionModel.find(query)
                .populate('roleId')
                .sort({ createdAt: -1 })
                .skip((page - 1) * limit)
                .limit(limit),
            PermissionModel.countDocuments(query),
        ]);

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách quyền thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async updatePermission(id: string, payload: IPermissionPayload): Promise<IApiResponse<IPermissions>> {
        const session = await mongoose.startSession();
        session.startTransaction();
        try {
            if (payload.roleId) {
                const existed = await PermissionModel.findOne({ roleId: payload.roleId, _id: { $ne: id } }).session(session);
                if (existed) {
                    throw new ApiError(400, 'Quyền cho role này đã tồn tại');
                }
            }

            const updatedPermission = await PermissionModel.findByIdAndUpdate(id, payload, { new: true, session }).populate('roleId');
            if (!updatedPermission) {
                throw new ApiError(404, 'Quyền không tồn tại');
            }

            // Đồng bộ cache Redis
            const role = updatedPermission.roleId as unknown as IRoles;
            if (role && role.name) {
                const key = RedisAdapter.genPermissionKey(role.name);
                await RedisAdapter.delete(key);
                if (updatedPermission.permissions && updatedPermission.permissions.length > 0) {
                    await RedisAdapter.sadd(key, ...updatedPermission.permissions);
                }
            }

            await session.commitTransaction();
            return {
                success: true,
                message: 'Permission updated successfully',
                data: updatedPermission,
            };
        } catch (error) {
            await session.abortTransaction();
            throw error;
        } finally {
            session.endSession();
        }
    }

    public async getPermissionsMe(roleName: string): Promise<IApiResponse<IPermissions>> {
        if (!roleName) {
            return {
                success: false,
                message: 'Không tìm thấy role cho người dùng này',
                data: null,
            };
        }

        const role = await RolesModel.findOne({ name: roleName });
        if (!role) {
            return {
                success: false,
                message: 'Không tìm thấy role cho người dùng này',
                data: null,
            };
        }

        const permissionRecord = await PermissionModel.findOne({ roleId: role._id });

        if (!permissionRecord) {
            return {
                success: false,
                message: 'Không tìm thấy quyền cho role này',
                data: null,
            };
        }
        return {
            success: true,
            message: 'Lấy quyền của tôi thành công',
