        };
    }

    public async deletePermission(id: string): Promise<IApiResponse<IPermissions>> {
        const session = await mongoose.startSession();
        session.startTransaction();
        try {
            const permissionToDelete = await PermissionModel.findById(id).populate('roleId').session(session);
            if (!permissionToDelete) {
                throw new ApiError(404, 'Quyền không tồn tại');
            }

            const deletedPermission = await PermissionModel.findByIdAndDelete(id).session(session);

            // Đồng bộ cache Redis
            const role = permissionToDelete.roleId as unknown as IRoles;
            if (role && role.name) {
                const key = RedisAdapter.genPermissionKey(role.name);
                await RedisAdapter.delete(key);
            }

            await session.commitTransaction();
            return {
                success: true,
                message: 'Permission deleted successfully',
                data: deletedPermission,
            };
        } catch (error) {
            await session.abortTransaction();
            throw error;
        } finally {
            session.endSession();
        }
    }

    public async getPermissionsByRoleName(roleName: string): Promise<string[]> {
        const role = await RolesModel.findOne({ name: roleName });
        if (!role) {
            return [];
        }

        const permissionRecord = await PermissionModel.findOne({ roleId: role._id });

        if (!permissionRecord) {
            return [];
        }

        return permissionRecord.permissions;
    }

    public async getPermissionsByRoleNameInCacheOfDB(roleName: string): Promise<string[]> {
        const key = RedisAdapter.genPermissionKey(roleName);
        try {

            let cachedPermissions = await RedisAdapter.smembers(key);
            if (cachedPermissions && cachedPermissions.length > 0) {
                return cachedPermissions;
            }

            if (PermissionService.callingPermissionMaps.has(key)) {
                return PermissionService.callingPermissionMaps.get(key) as Promise<string[]>;
            }

            try {
                const promise = this.getPermissionsByRoleName(roleName);
                PermissionService.callingPermissionMaps.set(key, promise);
                cachedPermissions = await promise;
            } finally {
                await RedisAdapter.sadd(key, ...cachedPermissions);
                PermissionService.callingPermissionMaps.delete(key);
            }

            return cachedPermissions;
        } catch (error) {
            logger.error(`[PermissionService][getPermissionsByRoleName] Error for role ${roleName}:`, error);

            const role = await RolesModel.findOne({ name: roleName });
            if (!role) return [];

            const permissionRecord = await PermissionModel.findOne({ roleId: role._id });
            return permissionRecord?.permissions || [];
        }
    }
}

import { IApiResponse, IPaginatedResponse, QueryFilter } from '@common/interfaces/response.interface';
import NikoEmotionsModel from './nikoEmotion.model';
import { ApiError } from '@common/utils/ApiError';
import {
    INikoEmotions,
    INikoEmotionPayload,
    ICompanyEmotionsResponse,
    INikoEmotionFilter,
    IHappiestPerson,
    INikoEmployeeEmotions,
} from '@common/interfaces/nikoEmotion.interface';
import moment from 'moment-timezone';
import { GlobalSettingService } from '@modules/globalSettings/globalSetting.service';
import { INikoEmotionType, IGlobalSettingKey } from '@common/utils/enum';
import { Types, PipelineStage } from 'mongoose';
import EmployeesModel from '@modules/employees/employees.model';
import { IEmployees } from '@common/interfaces/employee.interface';

export class NikoEmotionsService {
    public async getEmotionsByFilter(filter: INikoEmotionFilter): Promise<IPaginatedResponse<INikoEmployeeEmotions>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const employeeQuery: QueryFilter<IEmployees> = {};

        if (filter.departmentId) {
            employeeQuery.departmentId = new Types.ObjectId(String(filter.departmentId)) as unknown as string;
        }
        if (filter.employeeId) {
            employeeQuery._id = new Types.ObjectId(String(filter.employeeId));
        }

        const aggregateQuery: PipelineStage[] = [
            { $match: employeeQuery },
            {
                $lookup: {
                    from: 'niko-emotions',
                    let: { empId: '$_id' },
                    pipeline: [
                        {
                            $match: {
                                $expr: {
                                    $and: [
                                        { $eq: ['$employeeId', '$$empId'] },
                                        ...(filter.startDate && filter.endDate
                                            ? [
                                                  {
                                                      $gte: [
                                                          '$date',
                                                          moment(filter.startDate).tz('Asia/Ho_Chi_Minh').startOf('day').toDate(),
                                                      ],
                                                  },
                                                  {
                                                      $lte: [
                                                          '$date',
                                                          moment(filter.endDate).tz('Asia/Ho_Chi_Minh').endOf('day').toDate(),
                                                      ],
                                                  },
                                              ]
                                            : []),
                                    ],
                                },
                            },
                        },
                        { $sort: { date: -1 } },
                    ],
                    as: 'emotions',
                },
            },
            {
                $project: {
                    _id: 1,
                    fullName: 1,
                    code: 1,
                    avatar: 1,
                    departmentId: 1,
                    emotions: 1,
                },
            },
            { $sort: { fullName: 1 } },
        ];

        const [records, docCounter] = await Promise.all([
            EmployeesModel.aggregate(aggregateQuery)
                .skip((page - 1) * limit)
                .limit(limit),
            EmployeesModel.aggregate([{ $match: employeeQuery }, { $count: 'count' }]),
        ]);
        const count = docCounter[0]?.count || 0;

        return {
            data: records,
            success: true,
            message: 'Lấy lịch sử cảm xúc theo nhóm nhân viên thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    private async getNikoSettings() {
        const globalSettingService = new GlobalSettingService();
        const [workingDaysSet, startTimeSet, endTimeSet] = await Promise.all([
            globalSettingService.getOneGlobalSetting({ key: IGlobalSettingKey.NIKO_WORKING_DAYS }),
            globalSettingService.getOneGlobalSetting({ key: IGlobalSettingKey.NIKO_WORK_START_TIME }),
            globalSettingService.getOneGlobalSetting({ key: IGlobalSettingKey.NIKO_WORK_END_TIME }),
        ]);

        return {
            workingDays: workingDaysSet.data?.value
                ? workingDaysSet.data.value.split(',').map(Number)
                : [1, 2, 3, 4, 5],
            workStartTime: startTimeSet.data?.value || '08:00',
            workEndTime: endTimeSet.data?.value || '17:30',
        };
    }

    private async checkWorkTime(): Promise<void> {
        const settings = await this.getNikoSettings();

        const now = moment().tz('Asia/Ho_Chi_Minh');
        const dayOfWeek = now.day();

        if (!settings.workingDays.includes(dayOfWeek)) {
            throw new ApiError(403, 'Hôm nay không phải ngày làm việc, bạn không thể chấm cảm xúc');
        }

        const currentTime = now.format('HH:mm');
        if (currentTime < settings.workStartTime || currentTime > settings.workEndTime) {
            throw new ApiError(
                403,
                `Bạn chỉ có thể chấm cảm xúc trong khung giờ làm việc (${settings.workStartTime} - ${settings.workEndTime})`,
            );
        }
    }

    public async submitEmotion(employeeId: string, payload: INikoEmotionPayload): Promise<IApiResponse<INikoEmotions>> {
        await this.checkWorkTime();
        const date = moment().tz('Asia/Ho_Chi_Minh').startOf('day').toDate();

        // Kiểm tra xem đã chấm chưa
        const existed = await NikoEmotionsModel.findOne({
            employeeId: new Types.ObjectId(employeeId),
            date,
        });

        if (existed) {
            throw new ApiError(400, 'Bạn đã chấm cảm xúc cho ngày này rồi. Vui lòng cập nhật nếu muốn thay đổi.');
        }

        const result = await NikoEmotionsModel.create({
            employeeId: new Types.ObjectId(employeeId),
            date,
            emoji: payload.emoji,
        });

        return {
            success: true,
            message: 'Chấm cảm xúc thành công',
            data: result as unknown as INikoEmotions,
        };
    }

    public async updateEmotion(employeeId: string, payload: INikoEmotionPayload): Promise<IApiResponse<INikoEmotions>> {
        await this.checkWorkTime();
        const date = moment().tz('Asia/Ho_Chi_Minh').startOf('day').toDate();

        const result = await NikoEmotionsModel.findOneAndUpdate(
            {
                employeeId: new Types.ObjectId(employeeId),
                date,
            },
            { emoji: payload.emoji },
            { new: true },
        );

        if (!result) {
            throw new ApiError(404, 'Không tìm thấy dữ liệu chấm cảm xúc cho ngày này để cập nhật');
        }

        return {
            success: true,
            message: 'Cập nhật cảm xúc thành công',
            data: result as unknown as INikoEmotions,
        };
    }

    public async getAllCompanyEmotionsWithAverage(
        startDate?: string,
        endDate?: string,
    ): Promise<IApiResponse<ICompanyEmotionsResponse>> {
        const startDateTime = moment(startDate).tz('Asia/Ho_Chi_Minh').startOf('day').toDate();
        const endDateTime = moment(endDate).tz('Asia/Ho_Chi_Minh').endOf('day').toDate();
        const emotions = await NikoEmotionsModel.find({ date: { $gte: startDateTime, $lte: endDateTime } }).sort({
            date: -1,
        });

        if (!emotions || emotions.length === 0) {
            return {
                success: true,
                message: 'Chưa có dữ liệu cảm xúc nào',
                data: {
                    averageScore: 0,
                    totalRecords: 0,
                    emotionDistribution: {
                        [INikoEmotionType.TERRIBLE]: 0,
                        [INikoEmotionType.BAD]: 0,
                        [INikoEmotionType.NEUTRAL]: 0,
                        [INikoEmotionType.HAPPY]: 0,
                        [INikoEmotionType.EXCELLENT]: 0,
                    },
                },
            };
        }

        // Map cảm xúc sang điểm số (1-5)
        const emotionScoreMap: { [key: string]: number } = {
            [INikoEmotionType.TERRIBLE]: 1,
            [INikoEmotionType.BAD]: 2,
            [INikoEmotionType.NEUTRAL]: 3,
            [INikoEmotionType.HAPPY]: 4,
            [INikoEmotionType.EXCELLENT]: 5,
        };

        // Tính điểm trung bình
        let totalScore = 0;
        const emotionDistribution: { [key: string]: number } = {
            [INikoEmotionType.TERRIBLE]: 0,
            [INikoEmotionType.BAD]: 0,
            [INikoEmotionType.NEUTRAL]: 0,
            [INikoEmotionType.HAPPY]: 0,
            [INikoEmotionType.EXCELLENT]: 0,
        };

        emotions.forEach((emotion) => {
            const score = emotionScoreMap[emotion.emoji] || 0;
            totalScore += score;
            emotionDistribution[emotion.emoji] = (emotionDistribution[emotion.emoji] || 0) + 1;
        });

        const averageScore = totalScore / emotions.length;

        return {
            success: true,
            message: 'Lấy danh sách cảm xúc và điểm trung bình thành công',
            data: {
                averageScore: parseFloat(averageScore.toFixed(2)),
                totalRecords: emotions.length,
                emotionDistribution,
            },
        };
    }

    private getWorkingDaysCount(startDate: Date, endDate: Date, workingDays: number[]): number {
        let count = 0;
        const current = moment(startDate).clone();
        const last = moment(endDate);

        while (current.isSameOrBefore(last, 'day')) {
            if (workingDays.includes(current.day())) {
                count++;
            }
            current.add(1, 'days');
        }
        return count;
    }

    public async getHappiestPeopleRanking(filter: INikoEmotionFilter): Promise<IApiResponse<IHappiestPerson[]>> {
        const settings = await this.getNikoSettings();
        const workingDays = settings.workingDays;

        const startDate = filter.startDate
            ? moment(filter.startDate).tz('Asia/Ho_Chi_Minh').startOf('day').toDate()
            : moment().tz('Asia/Ho_Chi_Minh').startOf('isoWeek').toDate();

        const endDate = filter.endDate
            ? moment(filter.endDate).tz('Asia/Ho_Chi_Minh').endOf('day').toDate()
            : moment().tz('Asia/Ho_Chi_Minh').endOf('isoWeek').toDate();

        const now = moment().tz('Asia/Ho_Chi_Minh').endOf('day').toDate();
        const effectiveEndDate = endDate > now ? now : endDate;

        const workingDayCount = this.getWorkingDaysCount(startDate, effectiveEndDate, workingDays);

        const employeeMatch: QueryFilter<IEmployees> = {};

        if (filter.departmentId) {
            employeeMatch.departmentId = new Types.ObjectId(String(filter.departmentId)) as unknown as string;
        }

        const aggregation: PipelineStage[] = [
            { $match: employeeMatch },
            {
                $lookup: {
                    from: 'niko-emotions',
                    let: { empId: '$_id' },
                    pipeline: [
                        {
                            $match: {
                                $expr: {
                                    $and: [
                                        { $eq: ['$employeeId', '$$empId'] },
                                        { $gte: ['$date', startDate] },
                                        { $lte: ['$date', endDate] },
                                    ],
                                },
                            },
                        },
                    ],
                    as: 'emotions',
                },
            },
            {
                $addFields: {
                    totalRecords: { $size: '$emotions' },
                    totalScore: {
                        $reduce: {
                            input: '$emotions',
                            initialValue: 0,
                            in: {
                                $add: [
                                    '$$value',
                                    {
                                        $switch: {
                                            branches: [
                                                { case: { $eq: ['$$this.emoji', INikoEmotionType.TERRIBLE] }, then: 1 },
                                                { case: { $eq: ['$$this.emoji', INikoEmotionType.BAD] }, then: 2 },
                                                { case: { $eq: ['$$this.emoji', INikoEmotionType.NEUTRAL] }, then: 3 },
                                                { case: { $eq: ['$$this.emoji', INikoEmotionType.HAPPY] }, then: 4 },
                                                { case: { $eq: ['$$this.emoji', INikoEmotionType.EXCELLENT] }, then: 5 },
                                            ],
                                            default: 0,
                                        },
                                    },
                                ],
                            },
                        },
                    },
                },
            },
            {
                $addFields: {
                    averageScore: workingDayCount > 0 ? { $divide: ['$totalScore', workingDayCount] } : 0,
                },
            },
            {
                $sort: { averageScore: -1, totalRecords: -1, fullName: 1 },
            },
            {
                $limit: 5,
            },
            {
                $project: {
                    _id: 1,
                    averageScore: { $round: ['$averageScore', 2] },
                    totalRecords: 1,
                    employee: {
                        _id: '$_id',
                        fullName: '$fullName',
                        email: '$email',
                        avatar: '$avatar',
                        departmentId: '$departmentId',
                    },
                },
            },
        ];

        const data = await EmployeesModel.aggregate(aggregation);

        return {
            success: true,
            message: 'Lấy bảng xếp hạng những người hạnh phúc nhất thành công',
            data,
        };
    }
}

import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import { ApiError } from '@common/utils/ApiError';
import NikoOrdersModel from './nikoOrders.model';
import { INikoOrders, INikoOrdersFilter } from '@common/interfaces/nikoOrders.interface';
import NikoGiftCartsModel from '@modules/nikoGiftCarts/nikoGiftCarts.model';
import NikoWalletsModel from '@modules/nikoWallets/nikoWallets.model';
import { INikoOderOrderStatus, INikoOrderStatus } from '@common/utils/enum';
import { PipelineStage, QueryFilter } from 'mongoose';
import NikoGiftsModel from '@modules/nikoGifts/nikoGifts.model';
import moment from 'moment-timezone';
import mongoose from 'mongoose';
import { ICartItem } from '@common/interfaces/nikoGiftCarts.interface';

export class NikoOrdersService {
    public async createOrderFromCart(employeeId: string, payload: { giftIds: string[] }): Promise<IApiResponse<INikoOrders>> {
        const session = await mongoose.startSession();
        session.startTransaction();
        try {
            const cart = await NikoGiftCartsModel.findOne({ employeeId }).session(session);
            if (!cart || cart.items.length === 0) {
                throw new ApiError(400, 'Giỏ hàng đang trống');
            }

            const selectedCartItems = cart.items.filter(item =>
                payload.giftIds.includes(item.giftId.toString())
            );

            if (selectedCartItems.length !== payload.giftIds.length) {
                throw new ApiError(400, 'Một số quà tặng đã chọn không có trong giỏ hàng');
            }

            const startOfMonth = moment().tz('Asia/Ho_Chi_Minh').startOf('month').toDate();
            let totalOrderPrice = 0;
            const orderItems: ICartItem[] = [];

            for (const cartItem of selectedCartItems) {
                if (cartItem.quantity <= 0) {
                    throw new ApiError(400, `Số lượng quà tặng ${cartItem.giftName} phải lớn hơn 0`);
                }
                const gift = await NikoGiftsModel.findById(cartItem.giftId).session(session);
                if (!gift) {
                    throw new ApiError(404, `Không tìm thấy quà tặng: ${cartItem.giftName}`);
                }

                // 1. Check Month Limit (System-wide monthly limit)
                if (gift.monthLimit && gift.monthLimit > 0) {
                    const totalSystemOrdered = await NikoOrdersModel.aggregate([
                        {
                            $match: {
                                status: { $ne: INikoOrderStatus.CANCELLED },
                                createdAt: { $gte: startOfMonth },
                                'items.giftId': gift._id
                            }
                        },
                        { $unwind: '$items' },
                        { $match: { 'items.giftId': gift._id } },
                        { $group: { _id: null, total: { $sum: '$items.quantity' } } }
                    ]).session(session);

                    const currentSystemQty = totalSystemOrdered[0]?.total || 0;
                    if (currentSystemQty + cartItem.quantity > gift.monthLimit) {
                        throw new ApiError(400, `Quà tặng "${gift.name}" đã hết lượt đổi trong tháng này (Giới hạn hệ thống: ${gift.monthLimit})`);
                    }
                }

                // 2. Check User Limit (Personal monthly limit)
                if (gift.userLimit && gift.userLimit > 0) {
                    const totalUserOrdered = await NikoOrdersModel.aggregate([
                        {
                            $match: {
                                employeeId: cart.employeeId,
                                status: { $ne: INikoOrderStatus.CANCELLED },
                                createdAt: { $gte: startOfMonth },
                                'items.giftId': gift._id
                            }
                        },
                        { $unwind: '$items' },
                        { $match: { 'items.giftId': gift._id } },
                        { $group: { _id: null, total: { $sum: '$items.quantity' } } }
                    ]).session(session);

                    const currentUserQty = totalUserOrdered[0]?.total || 0;
                    if (currentUserQty + cartItem.quantity > gift.userLimit) {
                        throw new ApiError(400, `Bạn đã vượt quá giới hạn đổi quà tặng "${gift.name}" trong tháng này (Giới hạn của bạn: ${gift.userLimit})`);
                    }
                }

                const itemPrice = gift.stars * cartItem.quantity;
                totalOrderPrice += itemPrice;

                orderItems.push({
                    giftId: gift._id,
                    giftName: gift.name,
                    giftImage: gift.imageUrl,
                    price: gift.stars,
                    quantity: cartItem.quantity
                });

                const giftUpdateResult = await NikoGiftCartsModel.updateOne(
                    { _id: cart._id, __v: cart.__v, 'items.giftId': gift._id, 'items.quantity': { $gte: cartItem.quantity } },
                    { $inc: { 'items.$.quantity': -cartItem.quantity, __v: 1 } }
                ).session(session);

                if (giftUpdateResult.modifiedCount === 0) {
                    throw new ApiError(409, `Dữ liệu quà tặng "${gift.name}" đã được thay đổi. Vui lòng thử lại.`);
                }
            }

            const wallet = await NikoWalletsModel.findOne({ employeeId }).session(session);
            if (!wallet) {
                throw new ApiError(400, 'Không tìm thấy ví của bạn');
            }

            if (wallet.starsUsable < totalOrderPrice) {
                throw new ApiError(400, 'Bạn không đủ sao để thực hiện đổi quà');
            }

            // Create order
            const [newOrder] = await NikoOrdersModel.create([
                {
                    employeeId,
                    items: orderItems,
                    totalPrice: totalOrderPrice,
                    status: INikoOrderStatus.PENDING
                }
            ], { session });

            // Deduct stars
            const currentV = wallet.__v;
            const result = await NikoWalletsModel.updateOne({ _id: wallet._id, __v: currentV, starsUsable: { $gte: totalOrderPrice } }, { $inc: { starsUsable: -totalOrderPrice, __v: 1 } }).session(session);
            if (result.modifiedCount === 0) {
                throw new ApiError(409, 'Dữ liệu ví đã được thay đổi bởi một giao dịch khác. Vui lòng thử lại.');
            }

            await session.commitTransaction();
            return {
                success: true,
                message: 'Đặt quà thành công',
                data: newOrder,
            };
        } catch (error) {
            await session.abortTransaction();
            throw error;
        } finally {
            session.endSession();
        }
    }

    public async getMyOrders(employeeId: string, filter: INikoOrdersFilter): Promise<IPaginatedResponse<INikoOrders>> {
        const limit = Number(filter.limit) || 10;
        const page = Number(filter.page) || 1;
        const query: QueryFilter<INikoOrders> = { employeeId };

        if (filter.status) {
            query.status = filter.status;
        }

        const [records, count] = await Promise.all([
            NikoOrdersModel.find(query)
                .sort({ createdAt: -1 })
                .skip((page - 1) * limit)
                .limit(limit),
            NikoOrdersModel.countDocuments(query),
        ]);

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách đơn quà của bạn thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async getAllOrders(filter: INikoOrdersFilter): Promise<IPaginatedResponse<INikoOrders>> {
        const limit = Number(filter.limit) || 10;
        const page = Number(filter.page) || 1;
        const query: QueryFilter<INikoOrders> = {};

        if (filter.status) {
            query.status = filter.status;
        }
        if (filter.employeeId) {
            query.employeeId = filter.employeeId;
        }

        const aggregateQuery: PipelineStage[] = [
            { $match: query },
            { $sort: { createdAt: -1 } },
            { $skip: (page - 1) * limit },
            { $limit: limit },
            {
                $lookup: {
                    from: 'employees',
                    localField: 'employeeId',
                    foreignField: '_id',
                    as: 'employee',
                },
            },
            { $unwind: { path: '$employee', preserveNullAndEmptyArrays: true } }
        ];

        const [records, countRecords] = await Promise.all([
            NikoOrdersModel.aggregate(aggregateQuery),
            NikoOrdersModel.countDocuments(query),
        ]);

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách đơn quà thành công',
            meta: {
                totalItems: countRecords,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(countRecords / limit),
                currentPage: page,
            },
        };
    }

    public async updateOrderStatus(id: string, status: INikoOrderStatus): Promise<IApiResponse<INikoOrders>> {
        const session = await mongoose.startSession();
        session.startTransaction();
        try {
            const order = await NikoOrdersModel.findById(id).session(session);
            if (!order) {
                throw new ApiError(404, 'Không tìm thấy đơn quà');
            }

            if (INikoOderOrderStatus[status] <= INikoOderOrderStatus[order.status]) {
                throw new ApiError(400, 'Không thể cập nhật trạng thái đơn quà về quá khứ');
            }

            // If cancelling, refund stars and return items to cart
            if (status === INikoOrderStatus.CANCELLED && order.status !== INikoOrderStatus.CANCELLED) {
                // 1. Refund Stars
                const wallet = await NikoWalletsModel.findOne({ employeeId: order.employeeId }).session(session);
                if (wallet) {
                    const currentV = wallet.__v;
                    const result = await NikoWalletsModel.updateOne(
                        { _id: wallet._id, __v: currentV },
                        { $inc: { starsUsable: order.totalPrice, __v: 1 }, new: true }
                    ).session(session);

                    if (result.modifiedCount === 0) {
                        throw new ApiError(409, 'Dữ liệu ví đã được thay đổi. Vui lòng thử lại.');
                    }
                }

                // 2. Return Gift Quantities to Cart
                let cart = await NikoGiftCartsModel.findOne({ employeeId: order.employeeId }).session(session);
                if (!cart) {
                    cart = new NikoGiftCartsModel({ employeeId: order.employeeId, items: [], totalPrice: 0 });
                }

                for (const item of order.items) {
                    const existingItemIndex = cart.items.findIndex(i => i.giftId.toString() === item.giftId.toString());
                    if (existingItemIndex > -1) {
                        cart.items[existingItemIndex].quantity += item.quantity;
                    } else {
                        cart.items.push(item);
                    }
                }

                cart.totalPrice = cart.items.reduce((total, i) => total + (i.price * i.quantity), 0);
                await NikoGiftCartsModel.updateOne({ _id: cart._id, __v: cart.__v }, { $set: { items: cart.items, totalPrice: cart.totalPrice }, $inc: { __v: 1 } }).session(session);
            }

            const currentOrderV = order.__v;

            const result = await NikoOrdersModel.findOneAndUpdate({ _id: order._id, __v: currentOrderV }, { $set: { status }, $inc: { __v: 1 } }, { new: true }).session(session);
            if (!result) {
                throw new ApiError(409, 'Đơn hàng này đã được cập nhật bởi một người khác. Vui lòng làm mới trang.');
            }


            await session.commitTransaction();
            return {
                success: true,
                message: 'Cập nhật trạng thái đơn quà thành công',
                data: order,
            };
        } catch (error) {
            await session.abortTransaction();
            throw error;
        } finally {
            session.endSession();
        }
    }
}

import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import { ApiError } from '@common/utils/ApiError';
import NikoWalletsModel from './nikoWallets.model';
import { INikoWalletFilter, INikoWalletPayload, INikoWallets } from '@common/interfaces/nikoWallet.interface';
import { PipelineStage, QueryFilter } from 'mongoose';
import { IUserContext } from '@common/helpers/permission.helper';
import { UserRoleDefined } from '@common/utils/enum';

export class NikoWalletsService {
    public async createNikoWallet(payload: INikoWalletPayload): Promise<IApiResponse<INikoWallets>> {
        if (payload.employeeId) {
            const existedWallet = await NikoWalletsModel.findOne({ employeeId: payload.employeeId });
            if (existedWallet) {
                throw new ApiError(400, 'Ví của nhân viên đã tồn tại');
            }
        }

        const newWallet = await NikoWalletsModel.create(payload);
        return {
            success: true,
            message: 'Tạo ví thành công',
            data: newWallet,
        };
    }

    public async getNikoWalletByFilter(
        filter: INikoWalletFilter,
        userContext: IUserContext,
    ): Promise<IPaginatedResponse<INikoWallets>> {
        const limit = Number(filter.limit) || 10;
        const page = Number(filter.page) || 1;
        const query: QueryFilter<INikoWalletFilter> = {};

        const isAdmin = userContext && (userContext.roles === UserRoleDefined.HR || userContext.roles === UserRoleDefined.Admin || userContext.roles === UserRoleDefined.SuperAdmin);
        if (filter.employeeId && isAdmin) {
            query.employeeId = filter.employeeId;
        } else {
            query.employeeId = userContext.user.employeeId;
        }

        if (filter.status) {
            query.status = filter.status;
        }

        const aggregateQuery: PipelineStage[] = [{ $match: query }, { $sort: { createdAt: -1 } }];

        const [records, docCounter] = await Promise.all([
            NikoWalletsModel.aggregate([
                ...aggregateQuery,
                { $skip: (page - 1) * limit },
                { $limit: limit },
                {
                    $lookup: {
                        from: 'employees',
                        localField: 'employeeId',
                        foreignField: '_id',
                        as: 'employee',
                    },
                },
                {
                    $unwind: {
                        path: '$employee',
                        preserveNullAndEmptyArrays: true,
                    },
                },
            ]),
            NikoWalletsModel.aggregate([...aggregateQuery, { $count: 'count' }]),
        ]);

        const count = docCounter[0]?.count || 0;
        return {
            data: records,
            success: true,
            message: 'Lấy danh sách ví thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async getNikoWalletById(id: string): Promise<IApiResponse<INikoWallets>> {
        const record = await NikoWalletsModel.findById(id).populate('employeeId');
        if (!record) {
            throw new ApiError(404, 'Không tìm thấy ví này');
        }

        return {
            success: true,
            message: 'Đã thấy ví',
            data: record,
        };
    }

    public async getNikoWalletByEmployeeId(employeeId: string): Promise<IApiResponse<INikoWallets>> {
        const record = await NikoWalletsModel.findOne({ employeeId }).populate('employeeId');
        if (!record) {
            throw new ApiError(404, 'Không tìm thấy ví của nhân viên này');
        }

        return {
            success: true,
            message: 'Đã thấy ví',
            data: record,
        };
    }

    public async updateNikoWallet(
        id: string,
        payload: INikoWalletPayload,
        userContext: IUserContext,
    ): Promise<IApiResponse<INikoWallets>> {
        const isAdmin = userContext && (userContext.roles === UserRoleDefined.Admin || userContext.roles === UserRoleDefined.SuperAdmin);

        // Basic protection: only admins can update wallet directly for now, 
        // or we might need more specific logic later (e.g. system updating stars)
        if (!isAdmin) {
            throw new ApiError(403, 'Bạn không có quyền cập nhật ví');
        }

        const wallet = await NikoWalletsModel.findByIdAndUpdate(id, payload, { new: true });
        if (!wallet) {
            throw new ApiError(400, 'Ví không tồn tại');
        }

        return {
            success: true,
            message: 'Cập nhật ví thành công',
            data: wallet,
        };
    }

    public async deleteNikoWallet(id: string, userContext: IUserContext): Promise<IApiResponse<INikoWallets>> {
        const isAdmin = userContext && (userContext.roles === UserRoleDefined.Admin || userContext.roles === UserRoleDefined.SuperAdmin);
        if (!isAdmin) {
            throw new ApiError(403, 'Bạn không có quyền xóa ví');
        }

        const wallet = await NikoWalletsModel.findByIdAndDelete(id);
        if (!wallet) {
            throw new ApiError(400, 'Ví không tồn tại');
        }
        return {
            success: true,
            message: 'Xóa ví thành công',
            data: wallet,
        };
    }
}

import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
