import { IApiResponse } from '@common/interfaces/response.interface';
import { ApiError } from '@common/utils/ApiError';
import NikoGiftCartsModel from './nikoGiftCarts.model';
import NikoGiftsModel from '@modules/nikoGifts/nikoGifts.model';
import { INikoGiftCarts } from '@common/interfaces/nikoGiftCarts.interface';

export class NikoGiftCartsService {
    public async getCartByEmployeeId(employeeId: string): Promise<IApiResponse<INikoGiftCarts>> {
        let cart = await NikoGiftCartsModel.findOne({ employeeId });

        if (!cart) {
            cart = await NikoGiftCartsModel.create({
                employeeId,
                items: [],
                totalPrice: 0
            });
        }

        return {
            success: true,
            message: 'Lấy giỏ hàng thành công',
            data: cart,
        };
    }

    public async updateCart(employeeId: string, payload: { giftId: string, quantity: number }): Promise<IApiResponse<INikoGiftCarts>> {
        const cart = await NikoGiftCartsModel.findOne({ employeeId });

        if (!cart) {
            throw new ApiError(404, 'Không tìm thấy giỏ hàng');
        }

        const existingItemIndex = cart.items.findIndex(i => i.giftId.toString() === payload.giftId);
        if (existingItemIndex === -1) {
            throw new ApiError(404, 'Không tìm thấy sản phẩm này trong giỏ hàng');
        }

        if (payload.quantity === 0) {
            cart.items.splice(existingItemIndex, 1);
        } else {
            cart.items[existingItemIndex].quantity = payload.quantity;
        }

        cart.totalPrice = cart.items.reduce((total, i) => total + (i.price * i.quantity), 0);

        await cart.save();

        return {
            success: true,
            message: 'Cập nhật số lượng thành công',
            data: cart,
        };
    }

    public async deleteCart(employeeId: string): Promise<IApiResponse<null>> {
        await NikoGiftCartsModel.findOneAndDelete({ employeeId });
        return {
            success: true,
            message: 'Xóa giỏ hàng thành công',
            data: null,
        };
    }

    public async addItemsToCart(employeeId: string, payload: { items: { giftId: string, quantity: number }[] }): Promise<IApiResponse<INikoGiftCarts>> {
        let cart = await NikoGiftCartsModel.findOne({ employeeId });
        if (!cart) {
            cart = new NikoGiftCartsModel({ employeeId, items: [], totalPrice: 0 });
        }

        for (const item of payload.items) {
            const gift = await NikoGiftsModel.findById(item.giftId);
            if (!gift) {
                throw new ApiError(404, `Không tìm thấy quà tặng với ID: ${item.giftId}`);
            }

            const existingItemIndex = cart.items.findIndex(i => i.giftId.toString() === item.giftId.toString());
            if (existingItemIndex > -1) {
                cart.items[existingItemIndex].quantity += (item.quantity || 1);
            } else {
                cart.items.push({
                    giftId: gift._id,
                    giftName: gift.name,
                    giftImage: gift.imageUrl,
                    price: gift.stars,
                    quantity: item.quantity || 1
                });
            }
        }

        cart.totalPrice = cart.items.reduce((total, i) => total + (i.price * i.quantity), 0);
        await cart.save();

        return {
            success: true,
            message: 'Thêm vào giỏ hàng thành công',
            data: cart,
        };
    }
}

