import React, { useEffect, useState, useMemo } from "react";
import { Card, Tabs, Form, Input, Button, Upload, message, Typography, Space, Spin, Avatar, Modal, Row, Col } from "antd";
import {
  UserOutlined,
  LockOutlined,
  CameraOutlined,
  PhoneOutlined,
  MailOutlined,
  HomeOutlined,
  SolutionOutlined,
  EditOutlined,
  CalendarOutlined,
  IdcardOutlined,
  DeploymentUnitOutlined,
} from "@ant-design/icons";
import { useLoginByTokenQuery, useChangePasswordMutation } from "../../auth/services/authApi";
import { useGetEmployeeDetailQuery, useUpdateEmployeeMutation } from "../../employees/services/employeeApi";
import { useSearchParams } from "react-router-dom";
import { hasFormChanged, trimValues } from "../../../utils/formUtils";
import { handleError, handleSuccess } from "../../../utils/notificationUtils";
import dayjs from "dayjs";

const { Title, Text } = Typography;

const AccountPage: React.FC = () => {
  const [searchParams, setSearchParams] = useSearchParams();
  const activeTab = searchParams.get("tab") || "profile";
  const [form] = Form.useForm();
  const [editForm] = Form.useForm();
  const [passwordForm] = Form.useForm();
  const [loading, setLoading] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  // Lấy thông tin user hiện tại
  const { data: userData, refetch: refetchUser } = useLoginByTokenQuery(undefined);
  const userJson = userData as Record<string, any>;
  const employeeIdRaw = userJson?.record?.data?.employeeId || userJson?.data?.data?.employeeId || userJson?.data?.employeeId;
  const employeeId = employeeIdRaw?._id || employeeIdRaw;

  // Lấy chi tiết nhân viên
  const {
    data: detailData,
    isLoading: isFetching,
    refetch: refetchDetail,
  } = useGetEmployeeDetailQuery(employeeId, {
    skip: !employeeId,
  });

  const [updateEmployee] = useUpdateEmployeeMutation();
  const [changePassword, { isLoading: isChangingPassword }] = useChangePasswordMutation();

  // Avatar local state for preview
  const [avatarUrl, setAvatarUrl] = useState<string>("");

  useEffect(() => {
    if (detailData?.data) {
      const data = detailData.data;
      form.setFieldsValue({
        fullName: data.fullName,
        email: data.email,
        phone: data.phone,
        address: data.address,
        avatar: data.avatar,
        departmentName: data?.departmentId?.name || "N/A",
        positionName: data?.positionId?.name || "N/A",
      });
      setAvatarUrl(data.avatar || "");
    }
  }, [detailData, form]);

  const handleUpdateProfile = async (values: Record<string, any>) => {
    setLoading(true);
    try {
      const sanitizedValues = trimValues(values);
      await updateEmployee({ _id: employeeId, ...sanitizedValues }).unwrap();
      handleSuccess("Cập nhật hồ sơ thành công");
      setIsEditModalOpen(false);
      refetchUser();
      refetchDetail();
    } catch (error) {
      handleError(error, "Có lỗi xảy ra khi cập nhật hồ sơ");
    } finally {
      setLoading(false);
    }
  };

  const handleChangePassword = async (values: Record<string, any>) => {
    try {
      const payload = {
        currentPassword: values.oldPassword,
        changePassword: values.newPassword,
      };
      await changePassword(payload).unwrap();
      handleSuccess("Đổi mật khẩu thành công");
      passwordForm.resetFields();
    } catch (error) {
      handleError(error, "Có lỗi xảy ra khi đổi mật khẩu");
    }
  };

  const uploadProps = {
    name: "file",
    action: import.meta.env.VITE_API_UPLOAD,
    showUploadList: false,
    async onChange(info: any) {
      if (info.file.status === "uploading") {
        setLoading(true);
        return;
      }
      if (info.file.status === "done") {
        const imageUrl = info.file.response?.url;
        if (imageUrl) {
          try {
            await updateEmployee({ _id: employeeId, avatar: imageUrl }).unwrap();
            setAvatarUrl(imageUrl);
            message.success("Cập nhật ảnh đại diện thành công");
            // Reload data
            refetchUser();
            refetchDetail();
          } catch (error) {
            handleError(error, "Lỗi khi lưu ảnh đại diện");
          } finally {
            setLoading(false);
          }
        }
      } else if (info.file.status === "error") {
        setLoading(false);
        message.error("Tải ảnh lên thất bại");
      }
    },
  };

  const items = [
    {
      key: "profile",
      label: (
        <span>
          <UserOutlined /> Hồ sơ cá nhân
        </span>
      ),
      children: (
        <div className="py-6 flex flex-col gap-6">
          {/* Header Card: Avatar & Name */}
          <Card className="rounded-[2rem] border-none shadow-sm bg-white overflow-hidden">
            <div className="flex flex-col items-center py-4">
